{
  "name": "Guía de Pagos 2026",
  "description": "Planificador financiero interactivo para distribución de nómina y pago de deudas."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Wallet, 
  Calendar, 
  AlertCircle, 
  CheckCircle2, 
  TrendingDown, 
  DollarSign, 
  PiggyBank, 
  Download, 
  Printer,
  ArrowRight
} from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

// --- Types & Constants ---

interface Transaction {
  id: string;
  type: 'income' | 'fixed' | 'priority' | 'debt-min' | 'debt-capital' | 'savings';
  name: string;
  amount: number;
  critical?: boolean;
}

interface Period {
  dateStr: string;
  day: number;
  month: number; // 0-indexed (0 = Jan)
  year: number;
  totalIncome: number;
  transactions: Transaction[];
  endBalance: number; // Cash left over (savings)
  debtStatus: {
    amex: number;
    nu: number;
    bogota: number;
  };
  goalsStatus: {
    uni: number; // Remaining
    homologacion: number; // Remaining
  };
}

const INITIAL_INCOME = 5400000;
const INITIAL_SAVINGS_UNI = 3400000;

const FIXED_EXPENSES = {
  bebe: 300000, // Split equally
  emiliano: 100000, // Single payment
  internet: 110000, // Single payment
  renta: 1400000, // Single payment (20th)
};

const INITIAL_DEBTS = {
  amex: 1500000,
  nu: 2200000,
  bogota: 3170000,
  bogotaCuota: 320000,
};

const GOALS = {
  uniTotal: 7000000,
  homologacion: 800000,
};

// --- Helper Functions ---

const formatCOP = (value: number) => {
  return new Intl.NumberFormat('es-CO', {
    style: 'currency',
    currency: 'COP',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(value);
};

const getQuincenaDates = () => {
  // Generate dates from Jan 5 2026 to June 20 2026
  const dates = [];
  const startYear = 2026;
  // Jan (0) to June (5)
  for (let month = 0; month <= 5; month++) {
    dates.push({ day: 5, month, year: startYear });
    dates.push({ day: 20, month, year: startYear });
  }
  return dates;
};

const getMonthName = (monthIndex: number) => {
  const months = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
  return months[monthIndex];
};

export default function App() {
  const [income, setIncome] = useState(INITIAL_INCOME);
  const [savingsUni, setSavingsUni] = useState(INITIAL_SAVINGS_UNI);
  const [simulation, setSimulation] = useState<Period[]>([]);

  // Calculate the financial plan whenever inputs change
  useEffect(() => {
    const dates = getQuincenaDates();
    let currentUniPending = GOALS.uniTotal - savingsUni;
    let currentHomologacionPending = GOALS.homologacion;

    let debtAmex = INITIAL_DEBTS.amex;
    let debtNu = INITIAL_DEBTS.nu;
    let debtBogota = INITIAL_DEBTS.bogota;

    const newSimulation: Period[] = [];

    dates.forEach((dateObj, index) => {
      const { day, month, year } = dateObj;
      const dateStr = `${day} ${getMonthName(month)}`;
      const incomePerQuincena = income / 2;

      let cashAvailable = incomePerQuincena;
      const transactions: Transaction[] = [];

      // 1. Add Income
      transactions.push({
        id: `inc-${index}`,
        type: 'income',
        name: 'Nómina',
        amount: incomePerQuincena
      });

      // 2. Fixed Expenses
      // Bebé is split equally
      const bebeCost = FIXED_EXPENSES.bebe / 2;
      cashAvailable -= bebeCost;
      transactions.push({ id: `bebe-${index}`, type: 'fixed', name: 'Gastos Bebé', amount: bebeCost });

      if (day === 5) {
        // Emiliano & Internet on the 5th (arbitrary choice to balance cashflow, but usually bills are early)
        cashAvailable -= FIXED_EXPENSES.emiliano;
        transactions.push({ id: `emi-${index}`, type: 'fixed', name: 'Emiliano', amount: FIXED_EXPENSES.emiliano });

        cashAvailable -= FIXED_EXPENSES.internet;
        transactions.push({ id: `net-${index}`, type: 'fixed', name: 'Internet', amount: FIXED_EXPENSES.internet });
      } else { // 20th
        // Renta is strictly on the 20th
        cashAvailable -= FIXED_EXPENSES.renta;
        transactions.push({ id: `rent-${index}`, type: 'fixed', name: 'Arriendo', amount: FIXED_EXPENSES.renta, critical: true });
      }

      // 3. Priority Payments (Jan & Feb)

      // Homologacion (Strictly Jan, preferably Jan 5)
      if (currentHomologacionPending > 0 && month === 0) {
        const payAmount = Math.min(cashAvailable, currentHomologacionPending);
        if (payAmount > 0) {
          currentHomologacionPending -= payAmount;
          cashAvailable -= payAmount;
          transactions.push({ id: `homo-${index}`, type: 'priority', name: 'Homologación', amount: payAmount, critical: true });
        }
      }

      // University (Deadline Feb 5)
      // We prioritize this over debt capital, but NOT over debt minimums if possible to avoid default.
      // However, prompt says "University max payment until Feb 5".
      const isUniDeadline = (month === 1 && day === 5);
      const isUniPeriod = (month === 0) || isUniDeadline;

      // 4. Debt Minimums (Must be paid to avoid default)
      // Bogota Cuota Fija is on the 5th
      if (day === 5 && debtBogota > 0) {
        // Only pay quota if debt is higher than quota, else pay remaining debt
        const quota = Math.min(debtBogota, INITIAL_DEBTS.bogotaCuota);
        // If we are tight on Uni money, we still technically owe the bank.
        // Assuming we MUST pay the quota.
        if (cashAvailable >= quota) {
            debtBogota -= quota;
            cashAvailable -= quota;
            transactions.push({ id: `bogo-min-${index}`, type: 'debt-min', name: 'Cuota Banco Bogotá', amount: quota });
        } else {
             // This is a danger zone, but with 5.4m income this shouldn't happen based on fixed expenses
             const payWhatWeCan = cashAvailable;
             debtBogota -= payWhatWeCan;
             cashAvailable = 0;
             transactions.push({ id: `bogo-min-${index}`, type: 'debt-min', name: 'Abono Parcial Bogotá', amount: payWhatWeCan, critical: true });
        }
      }

      // 5. University Aggressive Payment (After minimums, before debt capital)
      if (currentUniPending > 0 && isUniPeriod) {
        const payAmount = Math.min(cashAvailable, currentUniPending);
        if (payAmount > 0) {
          currentUniPending -= payAmount;
          cashAvailable -= payAmount;
          transactions.push({ id: `uni-${index}`, type: 'priority', name: 'Universidad', amount: payAmount, critical: true });
        }
      }

      // 6. Debt Capital (Snowball)
      // Only if we have cash left.
      // Rules: AMEX (5th), NU (20th), Bogota (5th).

      if (cashAvailable > 0) {
        // AMEX (5th)
        if (day === 5 && debtAmex > 0) {
            const payAmount = Math.min(cashAvailable, debtAmex);
            debtAmex -= payAmount;
            cashAvailable -= payAmount;
            transactions.push({ id: `amex-${index}`, type: 'debt-capital', name: 'Capital AMEX', amount: payAmount });
        }

        // NU (20th)
        if (day === 20 && debtNu > 0) {
            const payAmount = Math.min(cashAvailable, debtNu);
            debtNu -= payAmount;
            cashAvailable -= payAmount;
            transactions.push({ id: `nu-${index}`, type: 'debt-capital', name: 'Capital NU', amount: payAmount });
        }

        // Bogota Extra (5th) - Only if AMEX is paid off or we want to split? 
        // Let's assume clear smaller debts or higher interest. AMEX is 1.5m, Bogota 3.1m. AMEX first is good.
        // If AMEX is done, put extra to Bogota on the 5th.
        if (day === 5 && debtBogota > 0 && cashAvailable > 0) {
             const payAmount = Math.min(cashAvailable, debtBogota);
             debtBogota -= payAmount;
             cashAvailable -= payAmount;
             transactions.push({ id: `bogo-cap-${index}`, type: 'debt-capital', name: 'Capital Extra Bogotá', amount: payAmount });
        }
      }

      // 7. Savings / Buffer
      if (cashAvailable > 0) {
        transactions.push({ id: `save-${index}`, type: 'savings', name: 'Disponible / Ahorro', amount: cashAvailable });
      }

      newSimulation.push({
        dateStr,
        day,
        month,
        year,
        totalIncome: incomePerQuincena,
        transactions,
        endBalance: cashAvailable,
        debtStatus: {
            amex: Math.max(0, debtAmex),
            nu: Math.max(0, debtNu),
            bogota: Math.max(0, debtBogota)
        },
        goalsStatus: {
            uni: Math.max(0, currentUniPending),
            homologacion: Math.max(0, currentHomologacionPending)
        }
      });
    });

    setSimulation(newSimulation);
  }, [income, savingsUni]);

  // --- Statistics ---

  const finalState = simulation[simulation.length - 1] || { 
      debtStatus: { amex: 0, nu: 0, bogota: 0 }, 
      goalsStatus: { uni: 0, homologacion: 0 } 
  };

  const totalDebtRemaining = finalState.debtStatus.amex + finalState.debtStatus.nu + finalState.debtStatus.bogota;
  const isUniPaid = simulation.find(p => p.month === 1 && p.day === 5)?.goalsStatus.uni === 0;

  const chartData = simulation.map(p => ({
    name: p.dateStr,
    Deuda: p.debtStatus.amex + p.debtStatus.nu + p.debtStatus.bogota,
    Uni: p.goalsStatus.uni
  }));

  // --- Handlers ---

  const handlePrint = () => window.print();

  const handleDownloadCSV = () => {
    let csv = "Fecha,Concepto,Tipo,Monto,Saldo Deuda Total\n";
    simulation.forEach(p => {
        const totalDebt = p.debtStatus.amex + p.debtStatus.nu + p.debtStatus.bogota;
        p.transactions.forEach(t => {
            csv += `${p.dateStr},${t.name},${t.type},${t.amount},${totalDebt}\n`;
        });
    });
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", "plan_financiero_2026.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen pb-12">

      {/* Header */}
      <header className="bg-slate-900 text-white py-8 px-4 md:px-8 print:py-4 print:px-0 print:bg-white print:text-black">
        <div className="max-w-5xl mx-auto">
          <div className="flex justify-between items-start md:items-center flex-col md:flex-row gap-4">
            <div>
              <h1 className="text-2xl md:text-3xl font-bold flex items-center gap-2">
                <Wallet className="text-emerald-400" />
                Plan Financiero 2026
              </h1>
              <p className="text-slate-400 mt-1 print:text-slate-600">
                Estrategia de pagos: Gastos Fijos &gt; Universidad &gt; Deudas
              </p>
            </div>
            <div className="flex gap-2 no-print">
               <button onClick={handleDownloadCSV} className="bg-slate-800 hover:bg-slate-700 text-white px-4 py-2 rounded-lg text-sm flex items-center gap-2 transition-colors">
                  <Download size={16} /> Exportar
               </button>
               <button onClick={handlePrint} className="bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg text-sm flex items-center gap-2 transition-colors shadow-lg shadow-emerald-900/20">
                  <Printer size={16} /> Imprimir
               </button>
            </div>
          </div>

          {/* KPI Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mt-8 print:mt-4 print:grid-cols-3">
             {/* Card 1: Uni Status */}
             <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 print:bg-slate-50 print:border-slate-300">
                <div className="flex items-center gap-2 text-slate-400 mb-2 text-sm font-medium">
                    <CheckCircle2 size={16} className={isUniPaid ? "text-emerald-400" : "text-yellow-400"} />
                    Meta Universidad (5 Feb)
                </div>
                <div className="text-2xl font-bold text-white print:text-slate-900">
                    {isUniPaid ? "CUBIERTO" : "FALTANTE"}
                </div>
                <div className="text-xs text-slate-400 mt-1">
                    Meta: {formatCOP(GOALS.uniTotal)}
                </div>
             </div>

             {/* Card 2: Debt Freedom */}
             <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 print:bg-slate-50 print:border-slate-300">
                <div className="flex items-center gap-2 text-slate-400 mb-2 text-sm font-medium">
                    <TrendingDown size={16} className="text-blue-400" />
                    Deuda Restante (Junio)
                </div>
                <div className="text-2xl font-bold text-white print:text-slate-900">
                    {formatCOP(totalDebtRemaining)}
                </div>
                <div className="text-xs text-slate-400 mt-1">
                    Inicial: {formatCOP(INITIAL_DEBTS.amex + INITIAL_DEBTS.nu + INITIAL_DEBTS.bogota)}
                </div>
             </div>

              {/* Card 3: Inputs (Interactive) */}
             <div className="bg-slate-700 p-4 rounded-xl border border-slate-600 print:hidden relative group">
                <div className="absolute right-2 top-2 opacity-0 group-hover:opacity-100 transition-opacity">
                    <span className="text-[10px] bg-slate-900 text-white px-2 py-1 rounded">Editable</span>
                </div>
                <div className="flex items-center justify-between mb-2">
                    <label className="text-slate-300 text-sm">Ahorro U Actual:</label>
                    <input 
                        type="number" 
                        value={savingsUni} 
                        onChange={(e) => setSavingsUni(Number(e.target.value))}
                        className="bg-slate-900 border border-slate-600 rounded px-2 py-1 text-right text-white w-32 text-sm focus:outline-none focus:border-emerald-500"
                    />
                </div>
                <div className="flex items-center justify-between">
                    <label className="text-slate-300 text-sm">Ingreso Total:</label>
                    <input 
                        type="number" 
                        value={income} 
                        onChange={(e) => setIncome(Number(e.target.value))}
                        className="bg-slate-900 border border-slate-600 rounded px-2 py-1 text-right text-white w-32 text-sm focus:outline-none focus:border-emerald-500"
                    />
                </div>
             </div>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 md:px-8 mt-8">

        {/* Chart Section */}
        <section className="mb-12 print:mb-6 print-break">
            <h2 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                <TrendingDown className="text-emerald-600" size={20}/>
                Proyección de Reducción de Deuda
            </h2>
            <div className="h-64 w-full bg-white p-4 rounded-xl shadow-sm border border-slate-200">
                <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={chartData} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                        <defs>
                            <linearGradient id="colorDeuda" x1="0" y1="0" x2="0" y2="1">
                                <stop offset="5%" stopColor="#ef4444" stopOpacity={0.1}/>
                                <stop offset="95%" stopColor="#ef4444" stopOpacity={0}/>
                            </linearGradient>
                            <linearGradient id="colorUni" x1="0" y1="0" x2="0" y2="1">
                                <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.1}/>
                                <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                            </linearGradient>
                        </defs>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                        <XAxis dataKey="name" fontSize={12} tickLine={false} axisLine={false} tickMargin={10} />
                        <YAxis hide />
                        <Tooltip 
                            formatter={(value: number) => formatCOP(value)}
                            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                        />
                        <Area type="monotone" dataKey="Deuda" stroke="#ef4444" fillOpacity={1} fill="url(#colorDeuda)" strokeWidth={2} />
                        <Area type="monotone" dataKey="Uni" stackId="1" stroke="#3b82f6" fillOpacity={1} fill="url(#colorUni)" strokeWidth={2} />
                    </AreaChart>
                </ResponsiveContainer>
            </div>
        </section>

        {/* Timeline Section */}
        <section>
            <h2 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
                <Calendar className="text-emerald-600" size={20}/>
                Hoja de Ruta Detallada
            </h2>

            <div className="grid gap-6 print:gap-4">
                {simulation.map((period, idx) => (
                    <div key={idx} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden print-break hover:shadow-md transition-shadow">

                        {/* Period Header */}
                        <div className="bg-slate-50 px-6 py-3 border-b border-slate-100 flex justify-between items-center">
                            <div className="flex items-center gap-3">
                                <div className="bg-white border border-slate-200 shadow-sm w-12 h-12 flex flex-col items-center justify-center rounded-lg text-slate-700 font-bold leading-tight">
                                    <span className="text-xs uppercase text-slate-400">{getMonthName(period.month)}</span>
                                    <span className="text-lg">{period.day}</span>
                                </div>
                                <div>
                                    <h3 className="font-semibold text-slate-800">
                                        {period.day === 5 ? 'Primera Quincena' : 'Segunda Quincena'}
                                    </h3>
                                    <p className="text-xs text-slate-500">
                                        Ingreso: <span className="text-emerald-600 font-medium">{formatCOP(period.totalIncome)}</span>
                                    </p>
                                </div>
                            </div>
                            <div className="text-right hidden sm:block">
                                <div className="text-xs text-slate-400 uppercase tracking-wider">Deuda Restante</div>
                                <div className="font-mono font-medium text-slate-700">
                                    {formatCOP(period.debtStatus.amex + period.debtStatus.nu + period.debtStatus.bogota)}
                                </div>
                            </div>
                        </div>

                        {/* Transactions List */}
                        <div className="p-4 sm:p-6 grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-2">
                            {/* Left Column: Fixed & Priority */}
                            <div>
                                <h4 className="text-xs font-semibold text-slate-400 uppercase mb-3 tracking-wider">Obligaciones</h4>
                                <ul className="space-y-2">
                                    {period.transactions.filter(t => ['fixed', 'priority', 'debt-min'].includes(t.type)).map(t => (
                                        <li key={t.id} className="flex justify-between items-center text-sm group">
                                            <div className="flex items-center gap-2">
                                                <div className={`w-1.5 h-1.5 rounded-full ${t.type === 'priority' ? 'bg-blue-500' : 'bg-slate-300'}`}></div>
                                                <span className={`${t.type === 'priority' ? 'font-medium text-blue-700' : 'text-slate-600'} ${t.critical ? 'text-red-600 font-medium' : ''}`}>
                                                    {t.name}
                                                </span>
                                            </div>
                                            <span className="text-slate-900 tabular-nums">-{formatCOP(t.amount)}</span>
                                        </li>
                                    ))}
                                </ul>
                            </div>

                            {/* Right Column: Capital & Savings */}
                            <div className="mt-4 md:mt-0">
                                <h4 className="text-xs font-semibold text-slate-400 uppercase mb-3 tracking-wider">Capital & Ahorro</h4>
                                <ul className="space-y-2">
                                    {period.transactions.filter(t => ['debt-capital', 'savings'].includes(t.type)).map(t => (
                                        <li key={t.id} className="flex justify-between items-center text-sm">
                                             <div className="flex items-center gap-2">
                                                <div className={`w-1.5 h-1.5 rounded-full ${t.type === 'debt-capital' ? 'bg-purple-500' : 'bg-emerald-400'}`}></div>
                                                <span className={`${t.type === 'debt-capital' ? 'font-medium text-purple-700' : 'text-emerald-700 font-medium'}`}>
                                                    {t.name}
                                                </span>
                                            </div>
                                            <span className="text-slate-900 tabular-nums">
                                                {t.type === 'savings' ? '' : '-'}{formatCOP(t.amount)}
                                            </span>
                                        </li>
                                    ))}
                                    {period.transactions.filter(t => ['debt-capital', 'savings'].includes(t.type)).length === 0 && (
                                        <li className="text-xs text-slate-400 italic py-1">
                                            Sin excedentes en este periodo.
                                        </li>
                                    )}
                                </ul>
                            </div>
                        </div>

                        {/* Alerts / Milestone Footer */}
                        {(period.month === 1 && period.day === 5 && period.goalsStatus.uni <= 0) && (
                            <div className="bg-blue-50 px-6 py-2 border-t border-blue-100 flex items-center gap-2 text-sm text-blue-800">
                                <CheckCircle2 size={16} />
                                <strong>Hito Cumplido:</strong> Universidad pagada en su totalidad.
                            </div>
                        )}
                        {(period.month === 0 && period.day === 5 && period.goalsStatus.homologacion <= 0) && (
                            <div className="bg-indigo-50 px-6 py-2 border-t border-indigo-100 flex items-center gap-2 text-sm text-indigo-800">
                                <CheckCircle2 size={16} />
                                <strong>Hito Cumplido:</strong> Homologación pagada.
                            </div>
                        )}
                         {(period.debtStatus.amex + period.debtStatus.nu + period.debtStatus.bogota === 0 && 
                           (idx > 0 && simulation[idx-1].debtStatus.amex + simulation[idx-1].debtStatus.nu + simulation[idx-1].debtStatus.bogota > 0)) && (
                            <div className="bg-emerald-100 px-6 py-2 border-t border-emerald-200 flex items-center gap-2 text-sm text-emerald-800 font-bold animate-pulse">
                                <PiggyBank size={16} />
                                ¡LIBRE DE DEUDAS!
                            </div>
                        )}

                    </div>
                ))}
            </div>
        </section>

        <footer className="mt-12 mb-8 text-center text-slate-400 text-xs print:hidden">
            <p>Los cálculos son estimados basados en los datos proporcionados. Revisa siempre tus extractos bancarios reales.</p>
        </footer>

      </main>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Wallet, 
  Calendar, 
  AlertCircle, 
  CheckCircle2, 
  TrendingDown, 
  DollarSign, 
  PiggyBank, 
  Download, 
  Printer,
  ArrowRight,
  TrendingUp
} from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar } from 'recharts';

// --- Types & Constants ---

interface Transaction {
  id: string;
  type: 'income' | 'fixed' | 'priority' | 'debt-min' | 'debt-capital' | 'savings';
  name: string;
  amount: number;
  critical?: boolean;
}

interface Period {
  dateStr: string;
  day: number;
  month: number; // 0-indexed (0 = Jan)
  year: number;
  totalIncome: number;
  transactions: Transaction[];
  endBalance: number; // Cash left over (savings)
  debtStatus: {
    amex: number;
    nu: number;
    bogota: number;
  };
  goalsStatus: {
    uni: number; // Remaining
    homologacion: number; // Remaining
  };
}

const INITIAL_INCOME = 5400000;
const INITIAL_SAVINGS_UNI = 3400000;

const FIXED_EXPENSES = {
  bebe: 300000, // Split equally
  emiliano: 100000, // Single payment
  internet: 110000, // Single payment
  renta: 1400000, // Single payment (20th)
};

const INITIAL_DEBTS = {
  amex: 1500000,
  nu: 2200000,
  bogota: 3170000,
  bogotaCuota: 320000,
};

const GOALS = {
  uniTotal: 7000000,
  homologacion: 800000,
};

// --- Helper Functions ---

const formatCOP = (value: number) => {
  return new Intl.NumberFormat('es-CO', {
    style: 'currency',
    currency: 'COP',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(value);
};

const getQuincenaDates = () => {
  // Generate dates from Jan 5 2026 to June 20 2026
  const dates = [];
  const startYear = 2026;
  // Jan (0) to June (5)
  for (let month = 0; month <= 5; month++) {
    dates.push({ day: 5, month, year: startYear });
    dates.push({ day: 20, month, year: startYear });
  }
  return dates;
};

const getMonthName = (monthIndex: number) => {
  const months = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
  return months[monthIndex];
};

export default function App() {
  const [income, setIncome] = useState(INITIAL_INCOME);
  const [savingsUni, setSavingsUni] = useState(INITIAL_SAVINGS_UNI);
  const [simulation, setSimulation] = useState<Period[]>([]);

  // Calculate the financial plan whenever inputs change
  useEffect(() => {
    const dates = getQuincenaDates();
    let currentUniPending = GOALS.uniTotal - savingsUni;
    let currentHomologacionPending = GOALS.homologacion;

    let debtAmex = INITIAL_DEBTS.amex;
    let debtNu = INITIAL_DEBTS.nu;
    let debtBogota = INITIAL_DEBTS.bogota;

    const newSimulation: Period[] = [];

    dates.forEach((dateObj, index) => {
      const { day, month, year } = dateObj;
      const dateStr = `${day} ${getMonthName(month)}`;
      const incomePerQuincena = income / 2;

      let cashAvailable = incomePerQuincena;
      const transactions: Transaction[] = [];

      // 1. Add Income
      transactions.push({
        id: `inc-${index}`,
        type: 'income',
        name: 'Nómina',
        amount: incomePerQuincena
      });

      // 2. Fixed Expenses
      // Bebé is split equally
      const bebeCost = FIXED_EXPENSES.bebe / 2;
      cashAvailable -= bebeCost;
      transactions.push({ id: `bebe-${index}`, type: 'fixed', name: 'Gastos Bebé', amount: bebeCost });

      if (day === 5) {
        // Emiliano & Internet on the 5th (arbitrary choice to balance cashflow, but usually bills are early)
        cashAvailable -= FIXED_EXPENSES.emiliano;
        transactions.push({ id: `emi-${index}`, type: 'fixed', name: 'Emiliano', amount: FIXED_EXPENSES.emiliano });

        cashAvailable -= FIXED_EXPENSES.internet;
        transactions.push({ id: `net-${index}`, type: 'fixed', name: 'Internet', amount: FIXED_EXPENSES.internet });
      } else { // 20th
        // Renta is strictly on the 20th
        cashAvailable -= FIXED_EXPENSES.renta;
        transactions.push({ id: `rent-${index}`, type: 'fixed', name: 'Arriendo', amount: FIXED_EXPENSES.renta, critical: true });
      }

      // 3. Priority Payments (Jan & Feb)

      // Homologacion (Strictly Jan, preferably Jan 5)
      if (currentHomologacionPending > 0 && month === 0) {
        const payAmount = Math.min(cashAvailable, currentHomologacionPending);
        if (payAmount > 0) {
          currentHomologacionPending -= payAmount;
          cashAvailable -= payAmount;
          transactions.push({ id: `homo-${index}`, type: 'priority', name: 'Homologación', amount: payAmount, critical: true });
        }
      }

      // University (Deadline Feb 5)
      // We prioritize this over debt capital, but NOT over debt minimums if possible to avoid default.
      // However, prompt says "University max payment until Feb 5".
      const isUniDeadline = (month === 1 && day === 5);
      const isUniPeriod = (month === 0) || isUniDeadline;

      // 4. Debt Minimums (Must be paid to avoid default)
      // Bogota Cuota Fija is on the 5th
      if (day === 5 && debtBogota > 0) {
        // Only pay quota if debt is higher than quota, else pay remaining debt
        const quota = Math.min(debtBogota, INITIAL_DEBTS.bogotaCuota);
        // If we are tight on Uni money, we still technically owe the bank.
        // Assuming we MUST pay the quota.
        if (cashAvailable >= quota) {
            debtBogota -= quota;
            cashAvailable -= quota;
            transactions.push({ id: `bogo-min-${index}`, type: 'debt-min', name: 'Cuota Banco Bogotá', amount: quota });
        } else {
             // This is a danger zone, but with 5.4m income this shouldn't happen based on fixed expenses
             const payWhatWeCan = cashAvailable;
             debtBogota -= payWhatWeCan;
             cashAvailable = 0;
             transactions.push({ id: `bogo-min-${index}`, type: 'debt-min', name: 'Abono Parcial Bogotá', amount: payWhatWeCan, critical: true });
        }
      }

      // 5. University Aggressive Payment (After minimums, before debt capital)
      if (currentUniPending > 0 && isUniPeriod) {
        const payAmount = Math.min(cashAvailable, currentUniPending);
        if (payAmount > 0) {
          currentUniPending -= payAmount;
          cashAvailable -= payAmount;
          transactions.push({ id: `uni-${index}`, type: 'priority', name: 'Universidad', amount: payAmount, critical: true });
        }
      }

      // 6. Debt Capital (Snowball)
      // Only if we have cash left.
      // Rules: AMEX (5th), NU (20th), Bogota (5th).

      if (cashAvailable > 0) {
        // AMEX (5th)
        if (day === 5 && debtAmex > 0) {
            const payAmount = Math.min(cashAvailable, debtAmex);
            debtAmex -= payAmount;
            cashAvailable -= payAmount;
            transactions.push({ id: `amex-${index}`, type: 'debt-capital', name: 'Capital AMEX', amount: payAmount });
        }

        // NU (20th)
        if (day === 20 && debtNu > 0) {
            const payAmount = Math.min(cashAvailable, debtNu);
            debtNu -= payAmount;
            cashAvailable -= payAmount;
            transactions.push({ id: `nu-${index}`, type: 'debt-capital', name: 'Capital NU', amount: payAmount });
        }

        // Bogota Extra (5th) - Only if AMEX is paid off or we want to split? 
        // Let's assume clear smaller debts or higher interest. AMEX is 1.5m, Bogota 3.1m. AMEX first is good.
        // If AMEX is done, put extra to Bogota on the 5th.
        if (day === 5 && debtBogota > 0 && cashAvailable > 0) {
             const payAmount = Math.min(cashAvailable, debtBogota);
             debtBogota -= payAmount;
             cashAvailable -= payAmount;
             transactions.push({ id: `bogo-cap-${index}`, type: 'debt-capital', name: 'Capital Extra Bogotá', amount: payAmount });
        }
      }

      // 7. Savings / Buffer
      if (cashAvailable > 0) {
        transactions.push({ id: `save-${index}`, type: 'savings', name: 'Disponible / Ahorro', amount: cashAvailable });
      }

      newSimulation.push({
        dateStr,
        day,
        month,
        year,
        totalIncome: incomePerQuincena,
        transactions,
        endBalance: cashAvailable,
        debtStatus: {
            amex: Math.max(0, debtAmex),
            nu: Math.max(0, debtNu),
            bogota: Math.max(0, debtBogota)
        },
        goalsStatus: {
            uni: Math.max(0, currentUniPending),
            homologacion: Math.max(0, currentHomologacionPending)
        }
      });
    });

    setSimulation(newSimulation);
  }, [income, savingsUni]);

  // --- Statistics ---

  const finalState = simulation[simulation.length - 1] || { 
      debtStatus: { amex: 0, nu: 0, bogota: 0 }, 
      goalsStatus: { uni: 0, homologacion: 0 } 
  };

  const totalDebtRemaining = finalState.debtStatus.amex + finalState.debtStatus.nu + finalState.debtStatus.bogota;
  const isUniPaid = simulation.find(p => p.month === 1 && p.day === 5)?.goalsStatus.uni === 0;

  const chartData = simulation.map(p => ({
    name: p.dateStr,
    Deuda: p.debtStatus.amex + p.debtStatus.nu + p.debtStatus.bogota,
    Uni: p.goalsStatus.uni
  }));

  // --- Savings Calculations ---

  const savingsData = useMemo(() => {
    let cumulative = 0;
    return simulation.map(p => {
      cumulative += p.endBalance;
      return {
        name: p.dateStr,
        cumulative: cumulative
      };
    });
  }, [simulation]);

  const monthlySavings = useMemo(() => {
    const grouped: { monthIndex: number; name: string; amount: number }[] = [];
    simulation.forEach(p => {
      const existing = grouped.find(g => g.monthIndex === p.month);
      if (existing) {
        existing.amount += p.endBalance;
      } else {
        grouped.push({
          monthIndex: p.month,
          name: getMonthName(p.month),
          amount: p.endBalance
        });
      }
    });
    return grouped;
  }, [simulation]);

  const totalPotentialSavings = savingsData.length > 0 ? savingsData[savingsData.length - 1].cumulative : 0;

  // --- Handlers ---

  const handlePrint = () => window.print();

  const handleDownloadCSV = () => {
    let csv = "Fecha,Concepto,Tipo,Monto,Saldo Deuda Total\n";
    simulation.forEach(p => {
        const totalDebt = p.debtStatus.amex + p.debtStatus.nu + p.debtStatus.bogota;
        p.transactions.forEach(t => {
            csv += `${p.dateStr},${t.name},${t.type},${t.amount},${totalDebt}\n`;
        });
    });
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", "plan_financiero_2026.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen pb-12">

      {/* Header */}
      <header className="bg-slate-900 text-white py-8 px-4 md:px-8 print:py-4 print:px-0 print:bg-white print:text-black">
        <div className="max-w-5xl mx-auto">
          <div className="flex justify-between items-start md:items-center flex-col md:flex-row gap-4">
            <div>
              <h1 className="text-2xl md:text-3xl font-bold flex items-center gap-2">
                <Wallet className="text-emerald-400" />
                Plan Financiero 2026
              </h1>
              <p className="text-slate-400 mt-1 print:text-slate-600">
                Estrategia de pagos: Gastos Fijos &gt; Universidad &gt; Deudas
              </p>
            </div>
            <div className="flex gap-2 no-print">
               <button onClick={handleDownloadCSV} className="bg-slate-800 hover:bg-slate-700 text-white px-4 py-2 rounded-lg text-sm flex items-center gap-2 transition-colors">
                  <Download size={16} /> Exportar
               </button>
               <button onClick={handlePrint} className="bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg text-sm flex items-center gap-2 transition-colors shadow-lg shadow-emerald-900/20">
                  <Printer size={16} /> Imprimir
               </button>
            </div>
          </div>

          {/* KPI Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mt-8 print:mt-4 print:grid-cols-3">
             {/* Card 1: Uni Status */}
             <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 print:bg-slate-50 print:border-slate-300">
                <div className="flex items-center gap-2 text-slate-400 mb-2 text-sm font-medium">
                    <CheckCircle2 size={16} className={isUniPaid ? "text-emerald-400" : "text-yellow-400"} />
                    Meta Universidad (5 Feb)
                </div>
                <div className="text-2xl font-bold text-white print:text-slate-900">
                    {isUniPaid ? "CUBIERTO" : "FALTANTE"}
                </div>
                <div className="text-xs text-slate-400 mt-1">
                    Meta: {formatCOP(GOALS.uniTotal)}
                </div>
             </div>

             {/* Card 2: Debt Freedom */}
             <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 print:bg-slate-50 print:border-slate-300">
                <div className="flex items-center gap-2 text-slate-400 mb-2 text-sm font-medium">
                    <TrendingDown size={16} className="text-blue-400" />
                    Deuda Restante (Junio)
                </div>
                <div className="text-2xl font-bold text-white print:text-slate-900">
                    {formatCOP(totalDebtRemaining)}
                </div>
                <div className="text-xs text-slate-400 mt-1">
                    Inicial: {formatCOP(INITIAL_DEBTS.amex + INITIAL_DEBTS.nu + INITIAL_DEBTS.bogota)}
                </div>
             </div>

              {/* Card 3: Inputs (Interactive) */}
             <div className="bg-slate-700 p-4 rounded-xl border border-slate-600 print:hidden relative group">
                <div className="absolute right-2 top-2 opacity-0 group-hover:opacity-100 transition-opacity">
                    <span className="text-[10px] bg-slate-900 text-white px-2 py-1 rounded">Editable</span>
                </div>
                <div className="flex items-center justify-between mb-2">
                    <label className="text-slate-300 text-sm">Ahorro U Actual:</label>
                    <input 
                        type="number" 
                        value={savingsUni} 
                        onChange={(e) => setSavingsUni(Number(e.target.value))}
                        className="bg-slate-900 border border-slate-600 rounded px-2 py-1 text-right text-white w-32 text-sm focus:outline-none focus:border-emerald-500"
                    />
                </div>
                <div className="flex items-center justify-between">
                    <label className="text-slate-300 text-sm">Ingreso Total:</label>
                    <input 
                        type="number" 
                        value={income} 
                        onChange={(e) => setIncome(Number(e.target.value))}
                        className="bg-slate-900 border border-slate-600 rounded px-2 py-1 text-right text-white w-32 text-sm focus:outline-none focus:border-emerald-500"
                    />
                </div>
             </div>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 md:px-8 mt-8">

        {/* Debt Chart Section */}
        <section className="mb-12 print:mb-6 print-break">
            <h2 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                <TrendingDown className="text-emerald-600" size={20}/>
                Proyección de Reducción de Deuda
            </h2>
            <div className="h-64 w-full bg-white p-4 rounded-xl shadow-sm border border-slate-200">
                <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={chartData} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                        <defs>
                            <linearGradient id="colorDeuda" x1="0" y1="0" x2="0" y2="1">
                                <stop offset="5%" stopColor="#ef4444" stopOpacity={0.1}/>
                                <stop offset="95%" stopColor="#ef4444" stopOpacity={0}/>
                            </linearGradient>
                            <linearGradient id="colorUni" x1="0" y1="0" x2="0" y2="1">
                                <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.1}/>
                                <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                            </linearGradient>
                        </defs>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                        <XAxis dataKey="name" fontSize={12} tickLine={false} axisLine={false} tickMargin={10} />
                        <YAxis hide />
                        <Tooltip 
                            formatter={(value: number) => formatCOP(value)}
                            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                        />
                        <Area type="monotone" dataKey="Deuda" stroke="#ef4444" fillOpacity={1} fill="url(#colorDeuda)" strokeWidth={2} />
                        <Area type="monotone" dataKey="Uni" stackId="1" stroke="#3b82f6" fillOpacity={1} fill="url(#colorUni)" strokeWidth={2} />
                    </AreaChart>
                </ResponsiveContainer>
            </div>
        </section>

        {/* Savings Section (NEW) */}
        <section className="mb-12 print:mb-6 print-break">
          <h2 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
            <PiggyBank className="text-emerald-600" size={20}/>
            Bolsita de Ahorro Acumulado
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="md:col-span-2 h-64 bg-white p-4 rounded-xl shadow-sm border border-slate-200">
               <ResponsiveContainer width="100%" height="100%">
                 <AreaChart data={savingsData} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                    <defs>
                        <linearGradient id="colorSavings" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#10b981" stopOpacity={0.2}/>
                            <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                        </linearGradient>
                    </defs>
                   <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                   <XAxis dataKey="name" fontSize={12} tickLine={false} axisLine={false} tickMargin={10} />
                   <YAxis hide />
                   <Tooltip 
                        formatter={(value: number) => [formatCOP(value), "Acumulado"]}
                        contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                    />
                   <Area type="monotone" dataKey="cumulative" stroke="#10b981" fill="url(#colorSavings)" strokeWidth={2} />
                 </AreaChart>
               </ResponsiveContainer>
            </div>

            <div className="bg-emerald-50 p-6 rounded-xl border border-emerald-100 flex flex-col justify-between">
                <div>
                    <h3 className="text-emerald-800 font-semibold mb-2 text-sm uppercase tracking-wide">Total Proyectado (Junio)</h3>
                    <p className="text-3xl font-bold text-emerald-600 mb-2">{formatCOP(totalPotentialSavings)}</p>
                    <p className="text-xs text-emerald-700 mb-4 leading-relaxed opacity-80">
                       Este es el capital libre acumulado si sigues el plan y no gastas los excedentes.
                    </p>
                </div>
                <div className="space-y-2 mt-2 max-h-40 overflow-y-auto pr-2 custom-scrollbar">
                    <h4 className="text-xs font-bold uppercase text-emerald-800 opacity-60 mb-2">Ahorro por Mes</h4>
                    {monthlySavings.map(m => (
                        <div key={m.name} className="flex justify-between text-sm text-emerald-900 border-b border-emerald-200/50 last:border-0 py-1.5">
                            <span>{m.name}</span>
                            <span className="font-medium">{formatCOP(m.amount)}</span>
                        </div>
                    ))}
                </div>
            </div>
          </div>
        </section>

        {/* Timeline Section */}
        <section>
            <h2 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
                <Calendar className="text-emerald-600" size={20}/>
                Hoja de Ruta Detallada
            </h2>

            <div className="grid gap-6 print:gap-4">
                {simulation.map((period, idx) => (
                    <div key={idx} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden print-break hover:shadow-md transition-shadow">

                        {/* Period Header */}
                        <div className="bg-slate-50 px-6 py-3 border-b border-slate-100 flex justify-between items-center">
                            <div className="flex items-center gap-3">
                                <div className="bg-white border border-slate-200 shadow-sm w-12 h-12 flex flex-col items-center justify-center rounded-lg text-slate-700 font-bold leading-tight">
                                    <span className="text-xs uppercase text-slate-400">{getMonthName(period.month)}</span>
                                    <span className="text-lg">{period.day}</span>
                                </div>
                                <div>
                                    <h3 className="font-semibold text-slate-800">
                                        {period.day === 5 ? 'Primera Quincena' : 'Segunda Quincena'}
                                    </h3>
                                    <p className="text-xs text-slate-500">
                                        Ingreso: <span className="text-emerald-600 font-medium">{formatCOP(period.totalIncome)}</span>
                                    </p>
                                </div>
                            </div>
                            <div className="text-right hidden sm:block">
                                <div className="text-xs text-slate-400 uppercase tracking-wider">Deuda Restante</div>
                                <div className="font-mono font-medium text-slate-700">
                                    {formatCOP(period.debtStatus.amex + period.debtStatus.nu + period.debtStatus.bogota)}
                                </div>
                            </div>
                        </div>

                        {/* Transactions List */}
                        <div className="p-4 sm:p-6 grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-2">
                            {/* Left Column: Fixed & Priority */}
                            <div>
                                <h4 className="text-xs font-semibold text-slate-400 uppercase mb-3 tracking-wider">Obligaciones</h4>
                                <ul className="space-y-2">
                                    {period.transactions.filter(t => ['fixed', 'priority', 'debt-min'].includes(t.type)).map(t => (
                                        <li key={t.id} className="flex justify-between items-center text-sm group">
                                            <div className="flex items-center gap-2">
                                                <div className={`w-1.5 h-1.5 rounded-full ${t.type === 'priority' ? 'bg-blue-500' : 'bg-slate-300'}`}></div>
                                                <span className={`${t.type === 'priority' ? 'font-medium text-blue-700' : 'text-slate-600'} ${t.critical ? 'text-red-600 font-medium' : ''}`}>
                                                    {t.name}
                                                </span>
                                            </div>
                                            <span className="text-slate-900 tabular-nums">-{formatCOP(t.amount)}</span>
                                        </li>
                                    ))}
                                </ul>
                            </div>

                            {/* Right Column: Capital & Savings */}
                            <div className="mt-4 md:mt-0">
                                <h4 className="text-xs font-semibold text-slate-400 uppercase mb-3 tracking-wider">Capital & Ahorro</h4>
                                <ul className="space-y-2">
                                    {period.transactions.filter(t => ['debt-capital', 'savings'].includes(t.type)).map(t => (
                                        <li key={t.id} className="flex justify-between items-center text-sm">
                                             <div className="flex items-center gap-2">
                                                <div className={`w-1.5 h-1.5 rounded-full ${t.type === 'debt-capital' ? 'bg-purple-500' : 'bg-emerald-400'}`}></div>
                                                <span className={`${t.type === 'debt-capital' ? 'font-medium text-purple-700' : 'text-emerald-700 font-medium'}`}>
                                                    {t.name}
                                                </span>
                                            </div>
                                            <span className="text-slate-900 tabular-nums">
                                                {t.type === 'savings' ? '' : '-'}{formatCOP(t.amount)}
                                            </span>
                                        </li>
                                    ))}
                                    {period.transactions.filter(t => ['debt-capital', 'savings'].includes(t.type)).length === 0 && (
                                        <li className="text-xs text-slate-400 italic py-1">
                                            Sin excedentes en este periodo.
                                        </li>
                                    )}
                                </ul>
                            </div>
                        </div>

                        {/* Alerts / Milestone Footer */}
                        {(period.month === 1 && period.day === 5 && period.goalsStatus.uni <= 0) && (
                            <div className="bg-blue-50 px-6 py-2 border-t border-blue-100 flex items-center gap-2 text-sm text-blue-800">
                                <CheckCircle2 size={16} />
                                <strong>Hito Cumplido:</strong> Universidad pagada en su totalidad.
                            </div>
                        )}
                        {(period.month === 0 && period.day === 5 && period.goalsStatus.homologacion <= 0) && (
                            <div className="bg-indigo-50 px-6 py-2 border-t border-indigo-100 flex items-center gap-2 text-sm text-indigo-800">
                                <CheckCircle2 size={16} />
                                <strong>Hito Cumplido:</strong> Homologación pagada.
                            </div>
                        )}
                         {(period.debtStatus.amex + period.debtStatus.nu + period.debtStatus.bogota === 0 && 
                           (idx > 0 && simulation[idx-1].debtStatus.amex + simulation[idx-1].debtStatus.nu + simulation[idx-1].debtStatus.bogota > 0)) && (
                            <div className="bg-emerald-100 px-6 py-2 border-t border-emerald-200 flex items-center gap-2 text-sm text-emerald-800 font-bold animate-pulse">
                                <PiggyBank size={16} />
                                ¡LIBRE DE DEUDAS!
                            </div>
                        )}

                    </div>
                ))}
            </div>
        </section>

        <footer className="mt-12 mb-8 text-center text-slate-400 text-xs print:hidden">
            <p>Los cálculos son estimados basados en los datos proporcionados. Revisa siempre tus extractos bancarios reales.</p>
        </footer>

      </main>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Wallet, 
  Calendar, 
  AlertCircle, 
  CheckCircle2, 
  TrendingDown, 
  DollarSign, 
  PiggyBank, 
  Download, 
  Printer,
  ArrowRight,
  TrendingUp,
  Search,
  ArrowUpDown,
  Filter
} from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar } from 'recharts';

// --- Types & Constants ---

interface Transaction {
  id: string;
  type: 'income' | 'fixed' | 'priority' | 'debt-min' | 'debt-capital' | 'savings';
  name: string;
  amount: number;
  critical?: boolean;
}

interface Period {
  dateStr: string;
  day: number;
  month: number; // 0-indexed (0 = Jan)
  year: number;
  totalIncome: number;
  transactions: Transaction[];
  endBalance: number; // Cash left over (savings)
  debtStatus: {
    amex: number;
    nu: number;
    bogota: number;
  };
  goalsStatus: {
    uni: number; // Remaining
    homologacion: number; // Remaining
  };
}

const INITIAL_INCOME = 5400000;
const INITIAL_SAVINGS_UNI = 3400000;

const FIXED_EXPENSES = {
  bebe: 300000, // Split equally
  emiliano: 100000, // Single payment
  internet: 110000, // Single payment
  renta: 1400000, // Single payment (20th)
};

const INITIAL_DEBTS = {
  amex: 1500000,
  nu: 2200000,
  bogota: 3170000,
  bogotaCuota: 320000,
};

const GOALS = {
  uniTotal: 7000000,
  homologacion: 800000,
};

// --- Helper Functions ---

const formatCOP = (value: number) => {
  return new Intl.NumberFormat('es-CO', {
    style: 'currency',
    currency: 'COP',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(value);
};

const getQuincenaDates = () => {
  // Generate dates from Jan 5 2026 to June 20 2026
  const dates = [];
  const startYear = 2026;
  // Jan (0) to June (5)
  for (let month = 0; month <= 5; month++) {
    dates.push({ day: 5, month, year: startYear });
    dates.push({ day: 20, month, year: startYear });
  }
  return dates;
};

const getMonthName = (monthIndex: number) => {
  const months = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
  return months[monthIndex];
};

// --- Sub-Components ---

function TransactionTable({ simulation }: { simulation: Period[] }) {
  const [searchTerm, setSearchTerm] = useState("");
  const [filterType, setFilterType] = useState<string>("all");
  const [sortConfig, setSortConfig] = useState<{ key: string; direction: 'asc' | 'desc' }>({ key: 'dateRaw', direction: 'asc' });

  // Flatten the data for the table
  const flatTransactions = useMemo(() => {
    return simulation.flatMap((period, pIdx) => 
      period.transactions.map((t, tIdx) => ({
        ...t,
        dateStr: period.dateStr,
        dateRaw: pIdx, // Use index as chronological proxy
        uniqueId: `${period.year}-${period.month}-${period.day}-${tIdx}`
      }))
    );
  }, [simulation]);

  // Filter and Sort
  const processedData = useMemo(() => {
    let data = [...flatTransactions];

    // Filter
    if (searchTerm) {
      const lower = searchTerm.toLowerCase();
      data = data.filter(t => 
        t.name.toLowerCase().includes(lower) || 
        t.dateStr.toLowerCase().includes(lower)
      );
    }
    if (filterType !== 'all') {
      data = data.filter(t => t.type === filterType);
    }

    // Sort
    data.sort((a, b) => {
      let aValue: any = a[sortConfig.key as keyof typeof a];
      let bValue: any = b[sortConfig.key as keyof typeof b];

      // Handle strings
      if (typeof aValue === 'string') {
        aValue = aValue.toLowerCase();
        bValue = bValue.toLowerCase();
      }

      if (aValue < bValue) return sortConfig.direction === 'asc' ? -1 : 1;
      if (aValue > bValue) return sortConfig.direction === 'asc' ? 1 : -1;
      return 0;
    });

    return data;
  }, [flatTransactions, searchTerm, filterType, sortConfig]);

  const requestSort = (key: string) => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const getTypeLabel = (type: string) => {
    const map: Record<string, string> = {
      'income': 'Ingreso',
      'fixed': 'Gasto Fijo',
      'priority': 'Prioridad',
      'debt-min': 'Deuda (Mín)',
      'debt-capital': 'Abono Capital',
      'savings': 'Ahorro'
    };
    return map[type] || type;
  };

  const getTypeColor = (type: string) => {
    const map: Record<string, string> = {
      'income': 'bg-emerald-100 text-emerald-800',
      'fixed': 'bg-slate-100 text-slate-800',
      'priority': 'bg-blue-100 text-blue-800',
      'debt-min': 'bg-orange-100 text-orange-800',
      'debt-capital': 'bg-purple-100 text-purple-800',
      'savings': 'bg-green-100 text-green-800'
    };
    return map[type] || 'bg-gray-100 text-gray-800';
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="p-4 border-b border-slate-100 bg-slate-50 flex flex-col md:flex-row gap-4 justify-between items-center">
        <h3 className="font-bold text-slate-800 flex items-center gap-2">
           <Filter size={18} className="text-slate-500" />
           Explorador de Movimientos
        </h3>

        <div className="flex flex-col md:flex-row gap-2 w-full md:w-auto">
           <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
              <input 
                type="text" 
                placeholder="Buscar concepto..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-9 pr-4 py-2 text-sm border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-500 w-full md:w-48"
              />
           </div>

           <select 
             value={filterType} 
             onChange={(e) => setFilterType(e.target.value)}
             className="px-4 py-2 text-sm border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-500 bg-white"
           >
             <option value="all">Todos los tipos</option>
             <option value="income">Ingresos</option>
             <option value="fixed">Gastos Fijos</option>
             <option value="priority">Prioritarios</option>
             <option value="debt-min">Cuotas Deuda</option>
             <option value="debt-capital">Abonos Capital</option>
             <option value="savings">Ahorro</option>
           </select>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-sm text-left">
          <thead className="text-xs text-slate-500 uppercase bg-slate-50 border-b border-slate-200">
            <tr>
              <th scope="col" className="px-6 py-3 cursor-pointer hover:bg-slate-100 transition-colors" onClick={() => requestSort('dateRaw')}>
                <div className="flex items-center gap-1">Fecha <ArrowUpDown size={14} /></div>
              </th>
              <th scope="col" className="px-6 py-3 cursor-pointer hover:bg-slate-100 transition-colors" onClick={() => requestSort('name')}>
                <div className="flex items-center gap-1">Concepto <ArrowUpDown size={14} /></div>
              </th>
              <th scope="col" className="px-6 py-3">
                Tipo
              </th>
              <th scope="col" className="px-6 py-3 text-right cursor-pointer hover:bg-slate-100 transition-colors" onClick={() => requestSort('amount')}>
                <div className="flex items-center justify-end gap-1">Monto <ArrowUpDown size={14} /></div>
              </th>
            </tr>
          </thead>
          <tbody>
            {processedData.map((t) => (
              <tr key={t.uniqueId} className="bg-white border-b border-slate-100 hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 font-medium text-slate-900 whitespace-nowrap">
                  {t.dateStr}
                </td>
                <td className="px-6 py-4 text-slate-700">
                  {t.name}
                </td>
                <td className="px-6 py-4">
                  <span className={`px-2 py-1 rounded-full text-xs font-semibold ${getTypeColor(t.type)}`}>
                    {getTypeLabel(t.type)}
                  </span>
                </td>
                <td className={`px-6 py-4 text-right font-mono font-medium ${t.type === 'income' ? 'text-emerald-600' : 'text-slate-700'}`}>
                  {t.type === 'income' ? '+' : '-'}{formatCOP(t.amount)}
                </td>
              </tr>
            ))}
            {processedData.length === 0 && (
              <tr>
                <td colSpan={4} className="px-6 py-8 text-center text-slate-400">
                  No se encontraron transacciones con los filtros actuales.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
      <div className="px-6 py-3 bg-slate-50 border-t border-slate-200 text-xs text-slate-500 flex justify-between">
         <span>Mostrando {processedData.length} movimientos</span>
         <span>Total filtrado: {formatCOP(processedData.reduce((acc, curr) => acc + (curr.type === 'income' ? 0 : curr.amount), 0))} (Salidas)</span>
      </div>
    </div>
  );
}


export default function App() {
  const [income, setIncome] = useState(INITIAL_INCOME);
  const [savingsUni, setSavingsUni] = useState(INITIAL_SAVINGS_UNI);
  const [simulation, setSimulation] = useState<Period[]>([]);

  // Calculate the financial plan whenever inputs change
  useEffect(() => {
    const dates = getQuincenaDates();
    let currentUniPending = GOALS.uniTotal - savingsUni;
    let currentHomologacionPending = GOALS.homologacion;

    let debtAmex = INITIAL_DEBTS.amex;
    let debtNu = INITIAL_DEBTS.nu;
    let debtBogota = INITIAL_DEBTS.bogota;

    const newSimulation: Period[] = [];

    dates.forEach((dateObj, index) => {
      const { day, month, year } = dateObj;
      const dateStr = `${day} ${getMonthName(month)}`;
      const incomePerQuincena = income / 2;

      let cashAvailable = incomePerQuincena;
      const transactions: Transaction[] = [];

      // 1. Add Income
      transactions.push({
        id: `inc-${index}`,
        type: 'income',
        name: 'Nómina',
        amount: incomePerQuincena
      });

      // 2. Fixed Expenses
      // Bebé is split equally
      const bebeCost = FIXED_EXPENSES.bebe / 2;
      cashAvailable -= bebeCost;
      transactions.push({ id: `bebe-${index}`, type: 'fixed', name: 'Gastos Bebé', amount: bebeCost });

      if (day === 5) {
        // Emiliano & Internet on the 5th (arbitrary choice to balance cashflow, but usually bills are early)
        cashAvailable -= FIXED_EXPENSES.emiliano;
        transactions.push({ id: `emi-${index}`, type: 'fixed', name: 'Emiliano', amount: FIXED_EXPENSES.emiliano });

        cashAvailable -= FIXED_EXPENSES.internet;
        transactions.push({ id: `net-${index}`, type: 'fixed', name: 'Internet', amount: FIXED_EXPENSES.internet });
      } else { // 20th
        // Renta is strictly on the 20th
        cashAvailable -= FIXED_EXPENSES.renta;
        transactions.push({ id: `rent-${index}`, type: 'fixed', name: 'Arriendo', amount: FIXED_EXPENSES.renta, critical: true });
      }

      // 3. Priority Payments (Jan & Feb)

      // Homologacion (Strictly Jan, preferably Jan 5)
      if (currentHomologacionPending > 0 && month === 0) {
        const payAmount = Math.min(cashAvailable, currentHomologacionPending);
        if (payAmount > 0) {
          currentHomologacionPending -= payAmount;
          cashAvailable -= payAmount;
          transactions.push({ id: `homo-${index}`, type: 'priority', name: 'Homologación', amount: payAmount, critical: true });
        }
      }

      // University (Deadline Feb 5)
      // We prioritize this over debt capital, but NOT over debt minimums if possible to avoid default.
      // However, prompt says "University max payment until Feb 5".
      const isUniDeadline = (month === 1 && day === 5);
      const isUniPeriod = (month === 0) || isUniDeadline;

      // 4. Debt Minimums (Must be paid to avoid default)
      // Bogota Cuota Fija is on the 5th
      if (day === 5 && debtBogota > 0) {
        // Only pay quota if debt is higher than quota, else pay remaining debt
        const quota = Math.min(debtBogota, INITIAL_DEBTS.bogotaCuota);
        // If we are tight on Uni money, we still technically owe the bank.
        // Assuming we MUST pay the quota.
        if (cashAvailable >= quota) {
            debtBogota -= quota;
            cashAvailable -= quota;
            transactions.push({ id: `bogo-min-${index}`, type: 'debt-min', name: 'Cuota Banco Bogotá', amount: quota });
        } else {
             // This is a danger zone, but with 5.4m income this shouldn't happen based on fixed expenses
             const payWhatWeCan = cashAvailable;
             debtBogota -= payWhatWeCan;
             cashAvailable = 0;
             transactions.push({ id: `bogo-min-${index}`, type: 'debt-min', name: 'Abono Parcial Bogotá', amount: payWhatWeCan, critical: true });
        }
      }

      // 5. University Aggressive Payment (After minimums, before debt capital)
      if (currentUniPending > 0 && isUniPeriod) {
        const payAmount = Math.min(cashAvailable, currentUniPending);
        if (payAmount > 0) {
          currentUniPending -= payAmount;
          cashAvailable -= payAmount;
          transactions.push({ id: `uni-${index}`, type: 'priority', name: 'Universidad', amount: payAmount, critical: true });
        }
      }

      // 6. Debt Capital (Snowball)
      // Only if we have cash left.
      // Rules: AMEX (5th), NU (20th), Bogota (5th).

      if (cashAvailable > 0) {
        // AMEX (5th)
        if (day === 5 && debtAmex > 0) {
            const payAmount = Math.min(cashAvailable, debtAmex);
            debtAmex -= payAmount;
            cashAvailable -= payAmount;
            transactions.push({ id: `amex-${index}`, type: 'debt-capital', name: 'Capital AMEX', amount: payAmount });
        }

        // NU (20th)
        if (day === 20 && debtNu > 0) {
            const payAmount = Math.min(cashAvailable, debtNu);
            debtNu -= payAmount;
            cashAvailable -= payAmount;
            transactions.push({ id: `nu-${index}`, type: 'debt-capital', name: 'Capital NU', amount: payAmount });
        }

        // Bogota Extra (5th) - Only if AMEX is paid off or we want to split? 
        // Let's assume clear smaller debts or higher interest. AMEX is 1.5m, Bogota 3.1m. AMEX first is good.
        // If AMEX is done, put extra to Bogota on the 5th.
        if (day === 5 && debtBogota > 0 && cashAvailable > 0) {
             const payAmount = Math.min(cashAvailable, debtBogota);
             debtBogota -= payAmount;
             cashAvailable -= payAmount;
             transactions.push({ id: `bogo-cap-${index}`, type: 'debt-capital', name: 'Capital Extra Bogotá', amount: payAmount });
        }
      }

      // 7. Savings / Buffer
      if (cashAvailable > 0) {
        transactions.push({ id: `save-${index}`, type: 'savings', name: 'Disponible / Ahorro', amount: cashAvailable });
      }

      newSimulation.push({
        dateStr,
        day,
        month,
        year,
        totalIncome: incomePerQuincena,
        transactions,
        endBalance: cashAvailable,
        debtStatus: {
            amex: Math.max(0, debtAmex),
            nu: Math.max(0, debtNu),
            bogota: Math.max(0, debtBogota)
        },
        goalsStatus: {
            uni: Math.max(0, currentUniPending),
            homologacion: Math.max(0, currentHomologacionPending)
        }
      });
    });

    setSimulation(newSimulation);
  }, [income, savingsUni]);

  // --- Statistics ---

  const finalState = simulation[simulation.length - 1] || { 
      debtStatus: { amex: 0, nu: 0, bogota: 0 }, 
      goalsStatus: { uni: 0, homologacion: 0 } 
  };

  const totalDebtRemaining = finalState.debtStatus.amex + finalState.debtStatus.nu + finalState.debtStatus.bogota;
  const isUniPaid = simulation.find(p => p.month === 1 && p.day === 5)?.goalsStatus.uni === 0;

  const chartData = simulation.map(p => ({
    name: p.dateStr,
    Deuda: p.debtStatus.amex + p.debtStatus.nu + p.debtStatus.bogota,
    Uni: p.goalsStatus.uni
  }));

  // --- Savings Calculations ---

  const savingsData = useMemo(() => {
    let cumulative = 0;
    return simulation.map(p => {
      cumulative += p.endBalance;
      return {
        name: p.dateStr,
        cumulative: cumulative
      };
    });
  }, [simulation]);

  const monthlySavings = useMemo(() => {
    const grouped: { monthIndex: number; name: string; amount: number }[] = [];
    simulation.forEach(p => {
      const existing = grouped.find(g => g.monthIndex === p.month);
      if (existing) {
        existing.amount += p.endBalance;
      } else {
        grouped.push({
          monthIndex: p.month,
          name: getMonthName(p.month),
          amount: p.endBalance
        });
      }
    });
    return grouped;
  }, [simulation]);

  const totalPotentialSavings = savingsData.length > 0 ? savingsData[savingsData.length - 1].cumulative : 0;

  // --- Handlers ---

  const handlePrint = () => window.print();

  const handleDownloadCSV = () => {
    let csv = "Fecha,Concepto,Tipo,Monto,Saldo Deuda Total\n";
    simulation.forEach(p => {
        const totalDebt = p.debtStatus.amex + p.debtStatus.nu + p.debtStatus.bogota;
        p.transactions.forEach(t => {
            csv += `${p.dateStr},${t.name},${t.type},${t.amount},${totalDebt}\n`;
        });
    });
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", "plan_financiero_2026.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen pb-12">

      {/* Header */}
      <header className="bg-slate-900 text-white py-8 px-4 md:px-8 print:py-4 print:px-0 print:bg-white print:text-black">
        <div className="max-w-5xl mx-auto">
          <div className="flex justify-between items-start md:items-center flex-col md:flex-row gap-4">
            <div>
              <h1 className="text-2xl md:text-3xl font-bold flex items-center gap-2">
                <Wallet className="text-emerald-400" />
                Plan Financiero 2026
              </h1>
              <p className="text-slate-400 mt-1 print:text-slate-600">
                Estrategia de pagos: Gastos Fijos &gt; Universidad &gt; Deudas
              </p>
            </div>
            <div className="flex gap-2 no-print">
               <button onClick={handleDownloadCSV} className="bg-slate-800 hover:bg-slate-700 text-white px-4 py-2 rounded-lg text-sm flex items-center gap-2 transition-colors">
                  <Download size={16} /> Exportar
               </button>
               <button onClick={handlePrint} className="bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg text-sm flex items-center gap-2 transition-colors shadow-lg shadow-emerald-900/20">
                  <Printer size={16} /> Imprimir
               </button>
            </div>
          </div>

          {/* KPI Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mt-8 print:mt-4 print:grid-cols-3">
             {/* Card 1: Uni Status */}
             <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 print:bg-slate-50 print:border-slate-300">
                <div className="flex items-center gap-2 text-slate-400 mb-2 text-sm font-medium">
                    <CheckCircle2 size={16} className={isUniPaid ? "text-emerald-400" : "text-yellow-400"} />
                    Meta Universidad (5 Feb)
                </div>
                <div className="text-2xl font-bold text-white print:text-slate-900">
                    {isUniPaid ? "CUBIERTO" : "FALTANTE"}
                </div>
                <div className="text-xs text-slate-400 mt-1">
                    Meta: {formatCOP(GOALS.uniTotal)}
                </div>
             </div>

             {/* Card 2: Debt Freedom */}
             <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 print:bg-slate-50 print:border-slate-300">
                <div className="flex items-center gap-2 text-slate-400 mb-2 text-sm font-medium">
                    <TrendingDown size={16} className="text-blue-400" />
                    Deuda Restante (Junio)
                </div>
                <div className="text-2xl font-bold text-white print:text-slate-900">
                    {formatCOP(totalDebtRemaining)}
                </div>
                <div className="text-xs text-slate-400 mt-1">
                    Inicial: {formatCOP(INITIAL_DEBTS.amex + INITIAL_DEBTS.nu + INITIAL_DEBTS.bogota)}
                </div>
             </div>

              {/* Card 3: Inputs (Interactive) */}
             <div className="bg-slate-700 p-4 rounded-xl border border-slate-600 print:hidden relative group">
                <div className="absolute right-2 top-2 opacity-0 group-hover:opacity-100 transition-opacity">
