import React, { useState, useEffect, useMemo } from 'react';
import { 
  Wallet, 
  Calendar, 
  AlertCircle, 
  CheckCircle2, 
  TrendingDown, 
  DollarSign, 
  PiggyBank, 
  Download, 
  Printer,
  ArrowRight,
  TrendingUp,
  Search,
  ArrowUpDown,
  Filter,
  ArrowUpCircle,
  ArrowDownCircle,
  Home,
  CreditCard,
  Briefcase,
  Landmark
} from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar } from 'recharts';

// --- Types & Constants ---

interface Transaction {
  id: string;
  type: 'income' | 'fixed' | 'priority' | 'debt-min' | 'debt-capital' | 'savings';
  name: string;
  amount: number;
  critical?: boolean;
}

interface Period {
  dateStr: string;
  day: number;
  month: number; // 0-indexed (0 = Jan)
  year: number;
  totalIncome: number;
  transactions: Transaction[];
  endBalance: number; // Cash left over (savings)
  debtStatus: {
    amex: number;
    nu: number;
    bogota: number;
  };
  goalsStatus: {
    uni: number; // Remaining
    homologacion: number; // Remaining
  };
}

const INITIAL_INCOME = 5400000;
const INITIAL_SAVINGS_UNI = 3400000;

const FIXED_EXPENSES = {
  bebe: 300000, // Split equally
  emiliano: 100000, // Single payment
  internet: 110000, // Single payment
  renta: 1400000, // Single payment (20th)
};

const INITIAL_DEBTS = {
  amex: 1500000,
  nu: 2200000,
  bogota: 3170000,
  bogotaCuota: 320000,
};

const GOALS = {
  uniTotal: 7000000,
  homologacion: 800000,
};

// --- Helper Functions ---

const formatCOP = (value: number) => {
  return new Intl.NumberFormat('es-CO', {
    style: 'currency',
    currency: 'COP',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(value);
};

const getQuincenaDates = () => {
  // Generate dates from Jan 5 2026 to June 20 2026
  const dates = [];
  const startYear = 2026;
  // Jan (0) to June (5)
  for (let month = 0; month <= 5; month++) {
    dates.push({ day: 5, month, year: startYear });
    dates.push({ day: 20, month, year: startYear });
  }
  return dates;
};

const getMonthName = (monthIndex: number) => {
  const months = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
  return months[monthIndex];
};

// --- Sub-Components ---

function TransactionTable({ simulation }: { simulation: Period[] }) {
  const [searchTerm, setSearchTerm] = useState("");
  const [filterType, setFilterType] = useState<string>("all");

  // Group and Filter Logic
  const groupedData = useMemo(() => {
    return simulation.map(period => {
      // Filter transactions inside the period
      let filteredTransactions = period.transactions;

      if (searchTerm) {
        const lower = searchTerm.toLowerCase();
        filteredTransactions = filteredTransactions.filter(t => 
          t.name.toLowerCase().includes(lower)
        );
      }

      if (filterType !== 'all') {
        filteredTransactions = filteredTransactions.filter(t => t.type === filterType);
      }

      // Calculate localized totals for visual headers
      const income = filteredTransactions.filter(t => t.type === 'income').reduce((acc, curr) => acc + curr.amount, 0);
      const expenses = filteredTransactions.filter(t => t.type !== 'income').reduce((acc, curr) => acc + curr.amount, 0);

      return {
        ...period,
        visibleTransactions: filteredTransactions,
        periodStats: { income, expenses }
      };
    }).filter(p => p.visibleTransactions.length > 0); // Hide periods with no matching transactions
  }, [simulation, searchTerm, filterType]);


  const getIconForType = (type: string) => {
    switch (type) {
      case 'income': return <ArrowUpCircle size={18} className="text-emerald-500" />;
      case 'fixed': return <Home size={18} className="text-slate-400" />;
      case 'priority': return <AlertCircle size={18} className="text-blue-500" />;
      case 'debt-min': return <CreditCard size={18} className="text-orange-500" />;
      case 'debt-capital': return <TrendingDown size={18} className="text-purple-500" />;
      case 'savings': return <PiggyBank size={18} className="text-emerald-600" />;
      default: return <Briefcase size={18} className="text-slate-400" />;
    }
  };

  const getTypeLabel = (type: string) => {
    const map: Record<string, string> = {
      'income': 'Ingreso',
      'fixed': 'Gasto Fijo',
      'priority': 'Prioridad',
      'debt-min': 'Deuda (Mín)',
      'debt-capital': 'Abono Capital',
      'savings': 'Ahorro'
    };
    return map[type] || type;
  };

  const getTypeStyle = (type: string) => {
     const map: Record<string, string> = {
      'income': 'bg-emerald-50 text-emerald-700 border-emerald-100',
      'fixed': 'bg-slate-50 text-slate-600 border-slate-200',
      'priority': 'bg-blue-50 text-blue-700 border-blue-100',
      'debt-min': 'bg-orange-50 text-orange-700 border-orange-100',
      'debt-capital': 'bg-purple-50 text-purple-700 border-purple-100',
      'savings': 'bg-green-50 text-green-700 border-green-100'
    };
    return map[type] || 'bg-gray-50 text-gray-600 border-gray-200';
  };

  return (
    <div className="space-y-6">
      {/* Filters Bar */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col md:flex-row gap-4 justify-between items-center sticky top-0 z-10 backdrop-blur-md bg-white/90">
        <h3 className="font-bold text-slate-800 flex items-center gap-2">
           <Filter size={20} className="text-emerald-600" />
           <span className="hidden sm:inline">Explorador de</span> Movimientos
        </h3>

        <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
           <div className="relative flex-1 sm:flex-none">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
              <input 
                type="text" 
                placeholder="Buscar (ej. Arriendo)..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-9 pr-4 py-2 text-sm border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-500 w-full sm:w-64 shadow-sm"
              />
           </div>

           <select 
             value={filterType} 
             onChange={(e) => setFilterType(e.target.value)}
             className="px-4 py-2 text-sm border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-500 bg-white shadow-sm"
           >
             <option value="all">Todo</option>
             <option value="income">Ingresos (+)</option>
             <option value="fixed">Gastos Fijos</option>
             <option value="priority">Prioritarios</option>
             <option value="debt-min">Cuotas Deuda</option>
             <option value="debt-capital">Abonos Capital</option>
             <option value="savings">Ahorro</option>
           </select>
        </div>
      </div>

      {/* Grouped Lists */}
      <div className="grid gap-6">
        {groupedData.map((period, idx) => (
          <div key={`${period.year}-${period.month}-${period.day}`} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden hover:shadow-md transition-shadow duration-300">

            {/* Group Header */}
            <div className="bg-slate-50/50 p-4 border-b border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between gap-3">
               <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-xl bg-white border border-slate-200 shadow-sm flex flex-col items-center justify-center text-slate-700">
                      <span className="text-[10px] font-bold uppercase tracking-tighter leading-none">{getMonthName(period.month)}</span>
                      <span className="text-lg font-bold leading-none">{period.day}</span>
                  </div>
                  <div>
                    <h4 className="font-semibold text-slate-800">
                      {period.day === 5 ? 'Primera Quincena' : 'Segunda Quincena'}
                    </h4>
                    <p className="text-xs text-slate-500 hidden sm:block">Movimientos detallados</p>
                  </div>
               </div>

               {/* Mini Stats for this period */}
               <div className="flex items-center gap-4 text-sm">
                  {period.periodStats.income > 0 && (
                     <div className="flex flex-col items-end">
                        <span className="text-[10px] uppercase text-slate-400 font-semibold tracking-wide">Entradas</span>
                        <span className="font-medium text-emerald-600">+{formatCOP(period.periodStats.income)}</span>
                     </div>
                  )}
                  {period.periodStats.expenses > 0 && (
                     <div className="flex flex-col items-end">
                        <span className="text-[10px] uppercase text-slate-400 font-semibold tracking-wide">Salidas</span>
                        <span className="font-medium text-slate-700">-{formatCOP(period.periodStats.expenses)}</span>
                     </div>
                  )}
               </div>
            </div>

            {/* Transactions Items */}
            <div className="divide-y divide-slate-50">
               {period.visibleTransactions.map((t, tIdx) => (
                 <div key={tIdx} className="p-4 flex items-center justify-between hover:bg-slate-50/80 transition-colors group">
                    <div className="flex items-center gap-4">
                       <div className={`w-10 h-10 rounded-full flex items-center justify-center bg-white border shadow-sm group-hover:scale-105 transition-transform ${t.type === 'income' ? 'border-emerald-100' : 'border-slate-100'}`}>
                          {getIconForType(t.type)}
                       </div>
                       <div className="flex flex-col">
                          <span className="text-sm font-medium text-slate-700">{t.name}</span>
                          <span className={`inline-flex self-start items-center px-2 py-0.5 rounded text-[10px] border ${getTypeStyle(t.type)}`}>
                             {getTypeLabel(t.type)}
                          </span>
                       </div>
                    </div>

                    <div className="text-right">
                       <span className={`block font-mono font-medium ${t.type === 'income' ? 'text-emerald-600' : 'text-slate-800'}`}>
                          {t.type === 'income' ? '+' : '-'}{formatCOP(t.amount)}
                       </span>
                       {t.critical && (
                          <span className="text-[10px] text-red-500 flex items-center justify-end gap-1 mt-0.5">
                             <AlertCircle size={10} /> Prioritario
                          </span>
                       )}
                    </div>
                 </div>
               ))}
            </div>
          </div>
        ))}

        {groupedData.length === 0 && (
          <div className="text-center py-12 bg-white rounded-xl border border-dashed border-slate-300">
             <div className="mx-auto w-12 h-12 bg-slate-100 rounded-full flex items-center justify-center mb-3">
