// --- Types & Constants ---

interface Transaction {
  id: string;
  type: 'income' | 'fixed' | 'priority' | 'debt-min' | 'debt-capital' | 'savings' | 'interest';
  name: string;
  amount: number;
  critical?: boolean;
}

interface Period {
  dateStr: string;
  day: number;
  month: number; // 0-indexed (0 = Jan)
  year: number;
  totalIncome: number;
  transactions: Transaction[];
  endBalance: number; // Cash left over (savings)
  debtStatus: {
    amex: number;
    nu: number;
    bogota: number;
  };
  goalsStatus: {
    uni: number; // Remaining
    homologacion: number; // Remaining
  };
}

interface DebtConfig {
  amex: number;
  nu: number;
  bogota: number;
  bogotaCuota: number;
}

interface FixedExpensesConfig {
  bebe: number;
  emiliano: number;
  internet: number;
  renta: number;
}

