function TransactionTable({ simulation }: { simulation: Period[] }) {
  const [searchTerm, setSearchTerm] = useState("");
  const [filterType, setFilterType] = useState<string>("all");

  // Group and Filter Logic
  const groupedData = useMemo(() => {
    return simulation.map(period => {
      // Filter transactions inside the period
      let filteredTransactions = period.transactions;

      if (searchTerm) {
        const lower = searchTerm.toLowerCase();
        filteredTransactions = filteredTransactions.filter(t => 
          t.name.toLowerCase().includes(lower)
        );
      }

      if (filterType !== 'all') {
        filteredTransactions = filteredTransactions.filter(t => t.type === filterType);
      }

      // Calculate localized totals for visual headers
      const income = filteredTransactions.filter(t => t.type === 'income').reduce((acc, curr) => acc + curr.amount, 0);
      const expenses = filteredTransactions.filter(t => t.type !== 'income').reduce((acc, curr) => acc + curr.amount, 0);

      return {
        ...period,
        visibleTransactions: filteredTransactions,
        periodStats: { income, expenses }
      };
    }).filter(p => p.visibleTransactions.length > 0); // Hide periods with no matching transactions
  }, [simulation, searchTerm, filterType]);


  const getIconForType = (type: string) => {
    switch (type) {
      case 'income': return <ArrowUpCircle size={18} className="text-emerald-500" />;
      case 'fixed': return <Home size={18} className="text-slate-400" />;
      case 'priority': return <AlertCircle size={18} className="text-blue-500" />;
      case 'debt-min': return <CreditCard size={18} className="text-orange-500" />;
      case 'interest': return <Percent size={18} className="text-orange-400" />;
      case 'debt-capital': return <TrendingDown size={18} className="text-purple-500" />;
      case 'savings': return <PiggyBank size={18} className="text-emerald-600" />;
      default: return <Briefcase size={18} className="text-slate-400" />;
    }
  };

  const getTypeLabel = (type: string) => {
    const map: Record<string, string> = {
      'income': 'Ingreso',
      'fixed': 'Gasto Fijo',
      'priority': 'Prioridad',
      'debt-min': 'Cuota Fija',
      'interest': 'Intereses',
      'debt-capital': 'Abono Capital',
      'savings': 'Ahorro'
    };
    return map[type] || type;
  };

  const getTypeStyle = (type: string) => {
     const map: Record<string, string> = {
      'income': 'bg-emerald-50 text-emerald-700 border-emerald-100',
      'fixed': 'bg-slate-50 text-slate-600 border-slate-200',
      'priority': 'bg-blue-50 text-blue-700 border-blue-100',
      'debt-min': 'bg-orange-50 text-orange-700 border-orange-100',
      'interest': 'bg-orange-50/50 text-orange-600/80 border-orange-100 dashed',
      'debt-capital': 'bg-purple-50 text-purple-700 border-purple-100',
      'savings': 'bg-green-50 text-green-700 border-green-100'
    };
    return map[type] || 'bg-gray-50 text-gray-600 border-gray-200';
  };

  return (
    <div className="space-y-6">
      {/* Filters Bar */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col md:flex-row gap-4 justify-between items-center sticky top-0 z-10 backdrop-blur-md bg-white/90">
        <h3 className="font-bold text-slate-800 flex items-center gap-2">
           <Filter size={20} className="text-emerald-600" />
           <span className="hidden sm:inline">Explorador de</span> Movimientos
        </h3>

        <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
           <div className="relative flex-1 sm:flex-none">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
              <input 
                type="text" 
                placeholder="Buscar (ej. Arriendo)..." 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-9 pr-4 py-2 text-sm border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-500 w-full sm:w-64 shadow-sm"
              />
           </div>

           <select 
             value={filterType} 
             onChange={(e) => setFilterType(e.target.value)}
             className="px-4 py-2 text-sm border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-500 bg-white shadow-sm"
           >
             <option value="all">Todo</option>
             <option value="income">Ingresos (+)</option>
             <option value="fixed">Gastos Fijos</option>
             <option value="priority">Prioritarios</option>
             <option value="debt-min">Cuotas Deuda</option>
             <option value="debt-capital">Abonos Capital</option>
             <option value="savings">Ahorro</option>
           </select>
        </div>
      </div>

      {/* Grouped Lists */}
      <div className="grid gap-6">
        {groupedData.map((period, idx) => (
          <div key={`${period.year}-${period.month}-${period.day}`} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden hover:shadow-md transition-shadow duration-300">

            {/* Group Header */}
            <div className="bg-slate-50/50 p-4 border-b border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between gap-3">
               <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-xl bg-white border border-slate-200 shadow-sm flex flex-col items-center justify-center text-slate-700">
                      <span className="text-[10px] font-bold uppercase tracking-tighter leading-none">{getMonthName(period.month)}</span>
                      <span className="text-lg font-bold leading-none">{period.day}</span>
                  </div>
                  <div>
                    <h4 className="font-semibold text-slate-800">
                      {period.day === 5 ? 'Primera Quincena' : 'Segunda Quincena'}
                    </h4>
                    <p className="text-xs text-slate-500 hidden sm:block">Movimientos detallados</p>
                  </div>
               </div>

               {/* Mini Stats for this period */}
               <div className="flex items-center gap-4 text-sm">
                  {period.periodStats.income > 0 && (
                     <div className="flex flex-col items-end">
                        <span className="text-[10px] uppercase text-slate-400 font-semibold tracking-wide">Entradas</span>
                        <span className="font-medium text-emerald-600">+{formatCOP(period.periodStats.income)}</span>
                     </div>
                  )}
                  {period.periodStats.expenses > 0 && (
                     <div className="flex flex-col items-end">
                        <span className="text-[10px] uppercase text-slate-400 font-semibold tracking-wide">Salidas</span>
                        <span className="font-medium text-slate-700">-{formatCOP(period.periodStats.expenses)}</span>
                     </div>
                  )}
               </div>
            </div>

            {/* Transactions Items */}
            <div className="divide-y divide-slate-50">
               {period.visibleTransactions.map((t, tIdx) => (
                 <div key={tIdx} className={`p-4 flex items-center justify-between hover:bg-slate-50/80 transition-colors group ${t.type === 'interest' ? 'opacity-70 bg-slate-50/30' : ''}`}>
                    <div className="flex items-center gap-4">
                       <div className={`w-10 h-10 rounded-full flex items-center justify-center bg-white border shadow-sm group-hover:scale-105 transition-transform ${t.type === 'income' ? 'border-emerald-100' : 'border-slate-100'}`}>
                          {getIconForType(t.type)}
                       </div>
                       <div className="flex flex-col">
                          <span className="text-sm font-medium text-slate-700">{t.name}</span>
                          <span className={`inline-flex self-start items-center px-2 py-0.5 rounded text-[10px] border ${getTypeStyle(t.type)}`}>
                             {getTypeLabel(t.type)}
                          </span>
                       </div>
                    </div>

                    <div className="text-right">
                       <span className={`block font-mono font-medium ${t.type === 'income' ? 'text-emerald-600' : 'text-slate-800'}`}>
                          {t.type === 'income' ? '+' : '-'}{formatCOP(t.amount)}
                       </span>
                       {t.critical && (
                          <span className="text-[10px] text-red-500 flex items-center justify-end gap-1 mt-0.5">
                             <AlertCircle size={10} /> Prioritario
                          </span>
                       )}
                    </div>
                 </div>
               ))}
            </div>
          </div>
        ))}

        {groupedData.length === 0 && (
          <div className="text-center py-12 bg-white rounded-xl border border-dashed border-slate-300">
             <div className="mx-auto w-12 h-12 bg-slate-100 rounded-full flex items-center justify-center mb-3">
                <Search className="text-slate-400" />
             </div>
             <p className="text-slate-500 font-medium">No se encontraron movimientos</p>
             <p className="text-slate-400 text-sm mt-1">Intenta cambiar los filtros de búsqueda</p>
          </div>
        )}
      </div>

      <div className="text-center text-xs text-slate-400 pt-4 pb-8">
         Mostrando {groupedData.length} periodos con coincidencias
      </div>
    </div>
  );
}


export default function App() {
  const [income, setIncome] = useState(INITIAL_INCOME);
  const [savingsUni, setSavingsUni] = useState(INITIAL_SAVINGS_UNI);
  const [interestRate, setInterestRate] = useState(2.2); // 2.2% monthly Estimate
  const [debts, setDebts] = useState<DebtConfig>(DEFAULT_DEBTS);
  const [fixedExpenses, setFixedExpenses] = useState<FixedExpensesConfig>(DEFAULT_FIXED_EXPENSES);
  const [showVariablesEditor, setShowVariablesEditor] = useState(false);
  const [simulation, setSimulation] = useState<Period[]>([]);

  // Calculate the financial plan whenever inputs change
  useEffect(() => {
    const dates = getQuincenaDates();
    let currentUniPending = GOALS.uniTotal - savingsUni;
    let currentHomologacionPending = GOALS.homologacion;

    // Initialize with State values instead of constants
    let debtAmex = debts.amex;
    let debtNu = debts.nu;
    let debtBogota = debts.bogota;

    const newSimulation: Period[] = [];

    dates.forEach((dateObj, index) => {
      const { day, month, year } = dateObj;
      const dateStr = `${day} ${getMonthName(month)}`;
      const incomePerQuincena = income / 2;

      let cashAvailable = incomePerQuincena;
      const transactions: Transaction[] = [];

      // 1. Add Income
      transactions.push({
        id: `inc-${index}`,
        type: 'income',
        name: 'Nómina',
        amount: incomePerQuincena
      });

      // 2. Fixed Expenses
      // Bebé is split equally
      const bebeCost = fixedExpenses.bebe / 2;
      cashAvailable -= bebeCost;
      transactions.push({ id: `bebe-${index}`, type: 'fixed', name: 'Gastos Bebé', amount: bebeCost });

      if (day === 5) {
        // Emiliano & Internet on the 5th (arbitrary choice to balance cashflow, but usually bills are early)
        cashAvailable -= fixedExpenses.emiliano;
        transactions.push({ id: `emi-${index}`, type: 'fixed', name: 'Emiliano', amount: fixedExpenses.emiliano });

        cashAvailable -= fixedExpenses.internet;
        transactions.push({ id: `net-${index}`, type: 'fixed', name: 'Internet', amount: fixedExpenses.internet });
      } else { // 20th
        // Renta is strictly on the 20th
        cashAvailable -= fixedExpenses.renta;
        transactions.push({ id: `rent-${index}`, type: 'fixed', name: 'Arriendo', amount: fixedExpenses.renta, critical: true });
      }

      // 3. Priority Payments (Jan & Feb)

      // Homologacion (Strictly Jan, preferably Jan 5)
      if (currentHomologacionPending > 0 && month === 0) {
        const payAmount = Math.min(cashAvailable, currentHomologacionPending);
        if (payAmount > 0) {
          currentHomologacionPending -= payAmount;
          cashAvailable -= payAmount;
          transactions.push({ id: `homo-${index}`, type: 'priority', name: 'Homologación', amount: payAmount, critical: true });
        }
      }

      // University (Deadline Feb 5)
      const isUniDeadline = (month === 1 && day === 5);
      const isUniPeriod = (month === 0) || isUniDeadline;

      // 4. Debt Minimums (Must be paid to avoid default)
      // Bogota Cuota Fija is on the 5th
      if (day === 5 && debtBogota > 0) {

        // --- LOGIC CHANGE: Interest Calculation ---
        // Estimate interest for the month based on current balance
        const estimatedInterest = Math.round(debtBogota * (interestRate / 100));

        // Quota is dynamic based on State
        let quotaToPay = debts.bogotaCuota;

        // If debt + interest is less than quota (end of loan), pay just that
        if ((debtBogota + estimatedInterest) < quotaToPay) {
            quotaToPay = debtBogota + estimatedInterest;
        }

        if (cashAvailable >= quotaToPay) {
            cashAvailable -= quotaToPay;

            // Split the payment: Interest vs Capital
            // Note: Interest doesn't reduce the debt principal, it just vanishes to the bank.
            const capitalContribution = Math.max(0, quotaToPay - estimatedInterest);

            debtBogota -= capitalContribution;

            // Visual separation for better understanding
            transactions.push({ 
                id: `bogo-min-${index}`, 
                type: 'debt-min', 
                name: 'Cuota Fija Banco Bogotá', 
                amount: quotaToPay 
            });

        } else {
             // Danger zone logic remains...
             const payWhatWeCan = cashAvailable;
             // Assume interest is paid first
             const capitalContribution = Math.max(0, payWhatWeCan - estimatedInterest);
             debtBogota -= capitalContribution;

             cashAvailable = 0;
             transactions.push({ id: `bogo-min-${index}`, type: 'debt-min', name: 'Abono Parcial Bogotá', amount: payWhatWeCan, critical: true });
        }
      }

      // 5. University Aggressive Payment (After minimums, before debt capital)
      if (currentUniPending > 0 && isUniPeriod) {
        const payAmount = Math.min(cashAvailable, currentUniPending);
        if (payAmount > 0) {
          currentUniPending -= payAmount;
          cashAvailable -= payAmount;
          transactions.push({ id: `uni-${index}`, type: 'priority', name: 'Universidad', amount: payAmount, critical: true });
        }
      }

      // 6. Debt Capital (Snowball)
      // Only if we have cash left.
      // Rules: AMEX (5th), NU (20th), Bogota (5th).

      if (cashAvailable > 0) {
        // AMEX (5th)
        if (day === 5 && debtAmex > 0) {
            const payAmount = Math.min(cashAvailable, debtAmex);
            debtAmex -= payAmount;
            cashAvailable -= payAmount;
            transactions.push({ id: `amex-${index}`, type: 'debt-capital', name: 'Capital AMEX', amount: payAmount });
        }

        // NU (20th)
        if (day === 20 && debtNu > 0) {
            const payAmount = Math.min(cashAvailable, debtNu);
            debtNu -= payAmount;
            cashAvailable -= payAmount;
            transactions.push({ id: `nu-${index}`, type: 'debt-capital', name: 'Capital NU', amount: payAmount });
        }

        // Bogota Extra (5th)
        // NOW: If AMEX is paid off, we dump extra cash into Bogota on the 5th.
        // Also if we have surplus on the 5th and AMEX is gone.
        if (day === 5 && debtBogota > 0 && cashAvailable > 0 && debtAmex <= 0) {
             const payAmount = Math.min(cashAvailable, debtBogota);
             debtBogota -= payAmount;
             cashAvailable -= payAmount;
             transactions.push({ id: `bogo-cap-${index}`, type: 'debt-capital', name: 'Abono Extra Bogotá', amount: payAmount });
        }

        // Bogota Extra (20th) - If NU is paid off!
        if (day === 20 && debtBogota > 0 && cashAvailable > 0 && debtNu <= 0) {
             const payAmount = Math.min(cashAvailable, debtBogota);
             debtBogota -= payAmount;
             cashAvailable -= payAmount;
             transactions.push({ id: `bogo-cap-20-${index}`, type: 'debt-capital', name: 'Abono Extra Bogotá', amount: payAmount });
        }
      }

      // 7. Savings / Buffer
      if (cashAvailable > 0) {
        transactions.push({ id: `save-${index}`, type: 'savings', name: 'Disponible / Ahorro', amount: cashAvailable });
      }

      newSimulation.push({
        dateStr,
        day,
        month,
        year,
        totalIncome: incomePerQuincena,
        transactions,
        endBalance: cashAvailable,
        debtStatus: {
            amex: Math.max(0, debtAmex),
            nu: Math.max(0, debtNu),
            bogota: Math.max(0, debtBogota)
        },
        goalsStatus: {
            uni: Math.max(0, currentUniPending),
            homologacion: Math.max(0, currentHomologacionPending)
        }
      });
    });

    setSimulation(newSimulation);
  }, [income, savingsUni, interestRate, debts, fixedExpenses]); 

  // --- Statistics ---

  const finalState = simulation[simulation.length - 1] || { 
      debtStatus: { amex: 0, nu: 0, bogota: 0 }, 
      goalsStatus: { uni: 0, homologacion: 0 } 
  };

  const totalDebtRemaining = finalState.debtStatus.amex + finalState.debtStatus.nu + finalState.debtStatus.bogota;
  const isUniPaid = simulation.find(p => p.month === 1 && p.day === 5)?.goalsStatus.uni === 0;

  const chartData = simulation.map(p => ({
    name: p.dateStr,
    Deuda: p.debtStatus.amex + p.debtStatus.nu + p.debtStatus.bogota,
    Uni: p.goalsStatus.uni
  }));

  // --- Savings Calculations ---

  const savingsData = useMemo(() => {
    let cumulative = 0;
    return simulation.map(p => {
      cumulative += p.endBalance;
      return {
        name: p.dateStr,
        cumulative: cumulative
      };
    });
  }, [simulation]);

  const monthlySavings = useMemo(() => {
    const grouped: { monthIndex: number; name: string; amount: number }[] = [];
    simulation.forEach(p => {
      const existing = grouped.find(g => g.monthIndex === p.month);
      if (existing) {
        existing.amount += p.endBalance;
      } else {
        grouped.push({
          monthIndex: p.month,
          name: getMonthName(p.month),
          amount: p.endBalance
        });
      }
    });
    return grouped;
  }, [simulation]);

  const totalPotentialSavings = savingsData.length > 0 ? savingsData[savingsData.length - 1].cumulative : 0;

  // --- Handlers ---

  const handlePrint = () => window.print();

  const handleDownloadCSV = () => {
    let csv = "Fecha,Concepto,Tipo,Monto,Saldo Deuda Total\n";
    simulation.forEach(p => {
        const totalDebt = p.debtStatus.amex + p.debtStatus.nu + p.debtStatus.bogota;
        p.transactions.forEach(t => {
            csv += `${p.dateStr},${t.name},${t.type},${t.amount},${totalDebt}\n`;
        });
    });
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", "plan_financiero_2026.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen pb-12">

      {/* Header */}
      <header className="bg-slate-900 text-white py-8 px-4 md:px-8 print:py-4 print:px-0 print:bg-white print:text-black">
        <div className="max-w-5xl mx-auto">
          <div className="flex justify-between items-start md:items-center flex-col md:flex-row gap-4 mb-4">
            <div>
              <h1 className="text-2xl md:text-3xl font-bold flex items-center gap-2">
                <Wallet className="text-emerald-400" />
                Plan Financiero 2026
              </h1>
              <p className="text-slate-400 mt-1 print:text-slate-600">
                Estrategia de pagos: Gastos Fijos &gt; Universidad &gt; Deudas
              </p>
            </div>
            <div className="flex flex-col md:flex-row gap-2 no-print">
               <button 
                  onClick={() => setShowVariablesEditor(!showVariablesEditor)}
                  className={`px-4 py-2 rounded-lg text-sm flex items-center gap-2 transition-colors ${showVariablesEditor ? 'bg-emerald-600 text-white' : 'bg-slate-800 hover:bg-slate-700 text-slate-200 border border-slate-700'}`}
               >
                  <Edit3 size={16} /> Ajuste de variables de pago
               </button>
               <button onClick={handleDownloadCSV} className="bg-slate-800 hover:bg-slate-700 text-white px-4 py-2 rounded-lg text-sm flex items-center gap-2 transition-colors border border-slate-700">
                  <Download size={16} /> Exportar
               </button>
               <button onClick={handlePrint} className="bg-slate-800 hover:bg-slate-700 text-white px-4 py-2 rounded-lg text-sm flex items-center gap-2 transition-colors border border-slate-700">
                  <Printer size={16} /> Imprimir
               </button>
            </div>
          </div>

          {/* Variables Editor Panel */}
          {showVariablesEditor && (
             <VariablesEditor 
                currentDebts={debts}
                currentExpenses={fixedExpenses}
                onClose={() => setShowVariablesEditor(false)}
                onSave={(newDebts, newExpenses) => {
                    setDebts(newDebts);
                    setFixedExpenses(newExpenses);
                }}
             />
          )}

          {/* KPI Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mt-8 print:mt-4 print:grid-cols-3">
             {/* Card 1: Uni Status */}
             <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 print:bg-slate-50 print:border-slate-300">
                <div className="flex items-center gap-2 text-slate-400 mb-2 text-sm font-medium">
                    <CheckCircle2 size={16} className={isUniPaid ? "text-emerald-400" : "text-yellow-400"} />
                    Meta Universidad (5 Feb)
                </div>
                <div className="text-2xl font-bold text-white print:text-slate-900">
                    {isUniPaid ? "CUBIERTO" : "FALTANTE"}
                </div>
                <div className="text-xs text-slate-400 mt-1">
                    Meta: {formatCOP(GOALS.uniTotal)}
                </div>
             </div>

             {/* Card 2: Debt Freedom */}
             <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 print:bg-slate-50 print:border-slate-300">
                <div className="flex items-center gap-2 text-slate-400 mb-2 text-sm font-medium">
                    <TrendingDown size={16} className="text-blue-400" />
                    Deuda Restante (Junio)
                </div>
                <div className="text-2xl font-bold text-white print:text-slate-900">
                    {formatCOP(totalDebtRemaining)}
                </div>
                <div className="text-xs text-slate-400 mt-1">
                    Inicial: {formatCOP(debts.amex + debts.nu + debts.bogota)}
                </div>
             </div>

              {/* Card 3: Inputs (Interactive) */}
             <div className="bg-slate-700 p-4 rounded-xl border border-slate-600 print:hidden relative group">
                <div className="absolute right-2 top-2 opacity-0 group-hover:opacity-100 transition-opacity">
                    <span className="text-[10px] bg-slate-900 text-white px-2 py-1 rounded">Editable</span>
                </div>
                <div className="space-y-1">
                  <div className="flex items-center justify-between">
                      <label className="text-slate-300 text-xs">Ahorro U Actual:</label>
                      <input 
