                      />
                  </div>
                  <div className="flex items-center justify-between">
                      <label className="text-slate-300 text-xs flex items-center gap-1"><Percent size={10} /> Tasa Crédito:</label>
                      <div className="relative w-28">
                        <input 
                            type="number" 
                            step="0.1"
                            value={interestRate} 
                            onChange={(e) => setInterestRate(Number(e.target.value))}
                            className="bg-slate-900 border border-slate-600 rounded px-2 py-0.5 text-right text-white w-full text-xs focus:outline-none focus:border-emerald-500 pr-5"
                        />
                        <span className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-500 text-[10px]">%</span>
                      </div>
                  </div>
                </div>
             </div>
          </div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 md:px-8 mt-8">

        {/* Debt Chart Section */}
