// --- Types & Constants ---

interface Transaction {
  id: string;
  type: 'income' | 'fixed' | 'priority' | 'debt-min' | 'debt-capital' | 'savings' | 'interest';
  name: string;
  amount: number;
  critical?: boolean;
}

interface Period {
  dateStr: string;
  day: number;
  month: number; // 0-indexed (0 = Jan)
  year: number;
  totalIncome: number;
  transactions: Transaction[];
  endBalance: number; // Cash left over (savings)
  debtStatus: {
    amex: number;
    nu: number;
    bogota: number;
  };
  goalsStatus: {
    uni: number; // Remaining
    homologacion: number; // Remaining
  };
}

interface DebtConfig {
  amex: number;
  nu: number;
  bogota: number;
  bogotaCuota: number;
}

interface FixedExpensesConfig {
  bebe: number;
  emiliano: number;
  internet: number;
  renta: number;
}

const INITIAL_INCOME = 5400000;
const INITIAL_SAVINGS_UNI = 3400000;

// Default Initial Values
const DEFAULT_FIXED_EXPENSES: FixedExpensesConfig = {
  bebe: 300000,
  emiliano: 100000,
  internet: 110000,
  renta: 1400000,
};

const DEFAULT_DEBTS: DebtConfig = {
  amex: 1500000,
  nu: 2200000,
  bogota: 3100000,
  bogotaCuota: 320000,
};

const GOALS = {
  uniTotal: 7000000,
  homologacion: 800000,
};

// --- Helper Functions ---

const formatCOP = (value: number) => {
  return new Intl.NumberFormat('es-CO', {
    style: 'currency',
    currency: 'COP',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(value);
};

const getQuincenaDates = () => {
  const dates = [];
  const startYear = 2026;
  for (let month = 0; month <= 5; month++) {
    dates.push({ day: 5, month, year: startYear });
    dates.push({ day: 20, month, year: startYear });
  }
  return dates;
};

const getMonthName = (monthIndex: number) => {
  const months = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
  return months[monthIndex];
};

