                          {t.type === 'income' ? '+' : '-'}{formatCOP(t.amount)}
                       </span>
                       {t.critical && (
                          <span className="text-[10px] text-red-500 font-bold flex items-center justify-end gap-1 mt-1 bg-red-50 px-1.5 py-0.5 rounded-full w-fit ml-auto">
                             Prioritario
                          </span>
                       )}
