            .reduce((sum, t) => sum + t.amount, 0);

        const current = monthlyMap.get(p.month) || 0;
        monthlyMap.set(p.month, current + periodSavings);
    });

    return Array.from(monthlyMap.entries())
        .sort((a, b) => a[0] - b[0])
        .map(([monthIndex, monthlyAmount]) => {
            accumulated += monthlyAmount;
            return {
