// --- Helper Functions ---

const formatCOP = (value: number) => {
  return new Intl.NumberFormat('es-CO', {
    style: 'currency',
    currency: 'COP',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(value);
};

const getQuincenaDates = (startDay: number, startMonth: number, startYear: number = 2026) => {
  const dates = [];
  let d = startDay;
  let m = startMonth;
  let y = startYear;

  for (let i = 0; i < 12; i++) { // Proyección de 6 meses (12 quincenas)
    dates.push({ day: d, month: m, year: y });

    if (d === 5) {
      d = 20;
    } else {
      d = 5;
      m++;
      if (m > 11) {
        m = 0;
        y++;
      }
    }
  }
  return dates;
};

const getMonthShortName = (monthIndex: number) => {
  const months = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
  return months[monthIndex];
};

