function TransactionTable({ simulation }: { simulation: Period[] }) {
  const [searchTerm, setSearchTerm] = useState("");
  const [filterType, setFilterType] = useState<string>("all");

  const groupedData = useMemo(() => {
    return simulation.map(period => {
      let filteredTransactions = period.transactions;
      if (searchTerm) {
        const lower = searchTerm.toLowerCase();
        filteredTransactions = filteredTransactions.filter(t => t.name.toLowerCase().includes(lower));
      }
      if (filterType !== 'all') {
        filteredTransactions = filteredTransactions.filter(t => t.type === filterType);
      }
      const income = filteredTransactions.filter(t => t.type === 'income').reduce((acc, curr) => acc + curr.amount, 0);
      const expenses = filteredTransactions.filter(t => t.type !== 'income').reduce((acc, curr) => acc + curr.amount, 0);
      return { ...period, visibleTransactions: filteredTransactions, periodStats: { income, expenses } };
    }).filter(p => p.visibleTransactions.length > 0);
  }, [simulation, searchTerm, filterType]);

  const getIconForType = (type: string) => {
    switch (type) {
      case 'income': return <ArrowUpCircle size={20} className="text-emerald-500" />;
      case 'fixed': return <Home size={18} className="text-slate-400" />;
      case 'priority': return <AlertCircle size={18} className="text-indigo-500" />;
      case 'debt-min': return <CreditCard size={18} className="text-orange-500" />;
      case 'interest': return <Percent size={18} className="text-orange-400" />;
      case 'debt-capital': return <TrendingDown size={18} className="text-purple-500" />;
      case 'savings': return <Wallet size={18} className="text-teal-600" />;
      default: return <Briefcase size={18} className="text-slate-400" />;
    }
  };

  const getTypeLabel = (type: string) => {
    const map: Record<string, string> = {
      'income': 'Ingreso Nómina',
      'fixed': 'Gasto Fijo',
      'priority': 'Prioridad Única',
      'debt-min': 'Cuota Obligatoria',
      'interest': 'Intereses',
      'debt-capital': 'Abono a Capital',
      'savings': 'Saldo a Favor'
    };
    return map[type] || type;
  };

  return (
    <div className="space-y-6">
      <div className="bg-white/80 backdrop-blur-md p-4 rounded-2xl shadow-sm border border-slate-200/60 flex flex-col md:flex-row gap-4 justify-between items-center sticky top-4 z-30 transition-all duration-300 hover:shadow-md">
        <h3 className="font-bold text-slate-800 flex items-center gap-2">
           <div className="bg-emerald-100 p-2 rounded-lg text-emerald-600"><Search size={18} /></div>
           Detalle de Movimientos
        </h3>
        <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
           <div className="relative flex-1 sm:flex-none">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
              <input type="text" placeholder="Buscar..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} className="pl-9 pr-4 py-2 text-sm bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-emerald-500/50 w-full sm:w-64" />
           </div>
           <select value={filterType} onChange={(e) => setFilterType(e.target.value)} className="px-4 py-2 text-sm bg-slate-50 border border-slate-200 rounded-xl cursor-pointer">
             <option value="all">Todo</option>
             <option value="income">💰 Ingresos</option>
             <option value="fixed">🏠 Fijos</option>
             <option value="priority">🚨 Prioritarios</option>
             <option value="debt-min">💳 Cuotas</option>
             <option value="debt-capital">📉 Abonos</option>
           </select>
        </div>
      </div>

      <div className="grid gap-6">
        {groupedData.map((period, idx) => (
          <div key={`${period.year}-${period.month}-${period.day}`} className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden group">
            <div className="bg-slate-50/50 p-5 border-b border-slate-100 flex flex-col sm:flex-row sm:items-center justify-between gap-3 group-hover:bg-slate-50 transition-colors">
               <div className="flex items-center gap-4">
                  <div className={`w-12 h-12 rounded-2xl border shadow-sm flex flex-col items-center justify-center ${period.day === 20 ? 'bg-orange-50 border-orange-100 text-orange-700' : 'bg-white border-slate-200 text-slate-700'}`}>
                      <span className="text-[10px] font-extrabold uppercase leading-none opacity-60">{getMonthShortName(period.month)}</span>
                      <span className="text-xl font-black leading-none">{period.day}</span>
                  </div>
                  <div>
                    <h4 className="font-bold text-slate-800 text-lg">{period.day === 5 ? 'Quincena 1' : 'Quincena 2'}</h4>
                    <p className="text-xs text-slate-500 font-medium">{period.day === 20 ? 'Pago Renta & NU' : 'Pago Servicios & Bogotá'}</p>
                  </div>
               </div>
               <div className="flex items-center gap-6 text-sm">
                  {period.periodStats.income > 0 && <div className="flex flex-col items-end"><span className="text-[10px] uppercase text-emerald-600/70 font-bold tracking-wider">Entra</span><span className="font-bold text-emerald-600">+{formatCOP(period.periodStats.income)}</span></div>}
                  {period.periodStats.expenses > 0 && <div className="flex flex-col items-end"><span className="text-[10px] uppercase text-slate-400 font-bold tracking-wider">Sale</span><span className="font-bold text-slate-600">-{formatCOP(period.periodStats.expenses)}</span></div>}
               </div>
            </div>
            <div className="divide-y divide-slate-50">
               {period.visibleTransactions.map((t, tIdx) => (
                 <div key={tIdx} className={`px-5 py-4 flex items-center justify-between hover:bg-slate-50/80 transition-all ${t.type === 'interest' ? 'opacity-60 bg-slate-50/30' : ''}`}>
                    <div className="flex items-center gap-4">
                       <div className={`w-10 h-10 rounded-full flex items-center justify-center bg-white border shadow-sm transition-transform ${t.type === 'income' ? 'border-emerald-100 bg-emerald-50/30' : 'border-slate-100'}`}>{getIconForType(t.type)}</div>
                       <div className="flex flex-col"><span className={`text-sm font-semibold ${t.critical ? 'text-red-600' : 'text-slate-700'}`}>{t.name}</span><span className="text-[11px] text-slate-400 font-medium">{getTypeLabel(t.type)}</span></div>
                    </div>
                    <div className="text-right">
                       <span className={`block font-mono font-bold text-sm ${t.type === 'income' ? 'text-emerald-600' : t.type === 'savings' ? 'text-teal-600' : 'text-slate-700'}`}>{t.type === 'income' ? '+' : t.type === 'savings' ? '=' : '-'}{formatCOP(t.amount)}</span>
                    </div>
                 </div>
               ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default function App() {
  const [income, setIncome] = useState(INITIAL_INCOME);
  const [debts, setDebts] = useState<DebtConfig>(DEFAULT_DEBTS);
  const [fixedExpenses, setFixedExpenses] = useState<FixedExpensesConfig>(DEFAULT_FIXED_EXPENSES);
  const [startDay, setStartDay] = useState(20);
  const [startMonth, setStartMonth] = useState(0); // Enero
  const [showVariablesEditor, setShowVariablesEditor] = useState(false);
  const [simulation, setSimulation] = useState<Period[]>([]);

  useEffect(() => {
    const dates = getQuincenaDates(startDay, startMonth);
    let currentHomologacionPending = GOALS.homologacion;
    let debtAmex = debts.amex;
    let debtNu = debts.nu;
    let debtBogota = debts.bogota;

    const newSimulation: Period[] = [];
    dates.forEach((dateObj, index) => {
      const { day, month, year } = dateObj;
      const dateStr = `${day} ${getMonthShortName(month)}`;
      const incomePerQuincena = income / 2;
      let cashAvailable = incomePerQuincena;
      const transactions: Transaction[] = [];

      transactions.push({ id: `inc-${index}`, type: 'income', name: 'Nómina', amount: incomePerQuincena });

      const bebeCost = fixedExpenses.bebe / 2;
      cashAvailable -= bebeCost;
      transactions.push({ id: `bebe-${index}`, type: 'fixed', name: 'Gastos Bebé (Mitad)', amount: bebeCost });

      if (day === 5) {
        cashAvailable -= fixedExpenses.emiliano;
        transactions.push({ id: `emi-${index}`, type: 'fixed', name: 'Emiliano', amount: fixedExpenses.emiliano });
        cashAvailable -= fixedExpenses.internet;
        transactions.push({ id: `net-${index}`, type: 'fixed', name: 'Internet', amount: fixedExpenses.internet });
      } else { 
        cashAvailable -= fixedExpenses.renta;
        transactions.push({ id: `rent-${index}`, type: 'fixed', name: 'Arriendo', amount: fixedExpenses.renta, critical: true });
      }

      // Homologación: Se paga lo más pronto posible desde el inicio del plan
      if (currentHomologacionPending > 0) {
        const payAmount = Math.min(cashAvailable, currentHomologacionPending);
        if (payAmount > 0) {
            currentHomologacionPending -= payAmount;
            cashAvailable -= payAmount;
            transactions.push({ id: `homo-${index}`, type: 'priority', name: 'Homologación (Prioridad)', amount: payAmount, critical: true });
        }
      }

      if (day === 5 && debtBogota > 0) {
        const quota = debts.bogotaCuota;
        if (cashAvailable >= quota) {
            cashAvailable -= quota;
            const interestApprox = debtBogota * 0.022; 
            const capitalPart = Math.max(0, quota - interestApprox);
            debtBogota -= capitalPart;
            transactions.push({ id: `bogo-min-${index}`, type: 'debt-min', name: 'Cuota Crédito Bogotá', amount: quota, critical: true });
        }
      }

      const SAFE_BUFFER = 150000;
      let investableCash = Math.max(0, cashAvailable - SAFE_BUFFER);

      if (day === 5) {
             if (debtAmex > 0) {
                 const payAmount = Math.min(cashAvailable, debtAmex);
                 debtAmex -= payAmount;
                 cashAvailable -= payAmount;
                 transactions.push({ id: `amex-${index}`, type: 'debt-capital', name: 'Pago Capital AMEX', amount: payAmount });
                 investableCash = Math.max(0, cashAvailable - SAFE_BUFFER);
             }
             if (investableCash > 0 && debtBogota > 0 && debtAmex <= 0) {
                 const payAmount = Math.min(investableCash, debtBogota);
                 debtBogota -= payAmount;
                 cashAvailable -= payAmount;
                 transactions.push({ id: `bogo-cap-${index}`, type: 'debt-capital', name: 'Abono Extra Bogotá', amount: payAmount });
             }
      }

      if (day === 20) {
            if (debtNu > 0) {
                const payAmount = Math.min(cashAvailable, debtNu); 
                debtNu -= payAmount;
                cashAvailable -= payAmount;
                transactions.push({ id: `nu-${index}`, type: 'debt-capital', name: 'Pago Capital NU', amount: payAmount });
            }
      }

      if (cashAvailable > 0) {
        const isDebtFree = (debtAmex + debtNu + debtBogota) <= 1000;
        transactions.push({ id: `save-${index}`, type: 'savings', name: isDebtFree ? 'Ahorro Libre' : 'Buffer de Emergencia', amount: cashAvailable });
      }

      newSimulation.push({
        dateStr, day, month, year,
        totalIncome: incomePerQuincena,
        transactions,
        endBalance: cashAvailable,
        debtStatus: { amex: Math.max(0, debtAmex), nu: Math.max(0, debtNu), bogota: Math.max(0, debtBogota) },
        goalsStatus: { homologacion: Math.max(0, currentHomologacionPending) }
      });
    });
    setSimulation(newSimulation);
  }, [income, debts, fixedExpenses, startDay, startMonth]); 

  const finalState = simulation[simulation.length - 1] || { debtStatus: { amex: 0, nu: 0, bogota: 0 }, goalsStatus: { homologacion: 0 } };
  const totalDebtRemaining = finalState.debtStatus.amex + finalState.debtStatus.nu + finalState.debtStatus.bogota;

  const chartData = simulation.map(p => ({ name: p.dateStr, Deuda: p.debtStatus.amex + p.debtStatus.nu + p.debtStatus.bogota }));
  const savingsData = useMemo(() => {
    let accumulated = 0;
    return simulation.map(p => {
        const periodSavings = p.transactions.filter(t => t.type === 'savings').reduce((sum, t) => sum + t.amount, 0);
        accumulated += periodSavings;
        return { name: p.dateStr, Acumulado: accumulated };
    });
  }, [simulation]);

  const handleDownloadCSV = () => {
    let csv = "Fecha,Concepto,Tipo,Monto,Saldo Deuda Total\n";
    simulation.forEach(p => {
        const totalDebt = p.debtStatus.amex + p.debtStatus.nu + p.debtStatus.bogota;
        p.transactions.forEach(t => { csv += `${p.dateStr},${t.name},${t.type},${t.amount},${totalDebt}\n`; });
    });
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", "plan_financiero_recalculado.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen pb-12 bg-slate-50 font-sans">
      <header className="relative overflow-hidden bg-slate-900 text-white pb-24 pt-10 px-4 md:px-8">
        <div className="absolute top-0 left-0 w-full h-full overflow-hidden z-0">
           <div className="absolute top-[-20%] right-[-10%] w-[500px] h-[500px] bg-emerald-600/10 rounded-full blur-[100px]"></div>
           <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-indigo-600/10 rounded-full blur-[100px]"></div>
        </div>

        <div className="max-w-6xl mx-auto relative z-10">
          <div className="flex justify-between items-start md:items-center flex-col md:flex-row gap-6 mb-8">
            <div>
              <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-slate-800/80 border border-slate-700 backdrop-blur-md mb-3 text-xs text-emerald-100">
                 <Clock size={12} className="text-emerald-400" /> Plan Dinámico Iniciando {startDay} de {MONTH_NAMES[startMonth]}
              </div>
              <h1 className="text-3xl md:text-5xl font-black tracking-tight">Estrategia 2026</h1>
              <p className="text-slate-400 mt-2 text-lg max-w-2xl font-light">Proyección financiera recalculada según fecha de ajuste y saldos actuales.</p>
            </div>
            <div className="flex flex-wrap gap-3 no-print">
               <button onClick={() => setShowVariablesEditor(!showVariablesEditor)} className={`px-5 py-2.5 rounded-xl text-sm font-semibold flex items-center gap-2 transition-all shadow-lg ${showVariablesEditor ? 'bg-white text-slate-900' : 'bg-slate-800/80 hover:bg-slate-700 text-white border border-slate-700'}`}><Edit3 size={18} /> Ajustar Plan</button>
               <button onClick={handleDownloadCSV} className="bg-slate-800/80 hover:bg-slate-700 text-white px-5 py-2.5 rounded-xl text-sm font-semibold flex items-center gap-2 transition-all border border-slate-700"><Download size={18} /> Exportar</button>
            </div>
          </div>
          {showVariablesEditor && (
             <VariablesEditor currentDebts={debts} currentExpenses={fixedExpenses} startDay={startDay} startMonth={startMonth} onClose={() => setShowVariablesEditor(false)} onSave={(newDebts, newExpenses, day, month) => {
                    setDebts(newDebts);
                    setFixedExpenses(newExpenses);
                    setStartDay(day);
                    setStartMonth(month);
                }} />
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 md:px-8 -mt-16 relative z-20">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
             <div className="bg-white p-6 rounded-2xl shadow-xl border border-slate-100">
                <div className="flex justify-between items-start mb-4"><div className="p-3 bg-indigo-50 rounded-xl text-indigo-600"><GraduationCap size={24} /></div></div>
                <h3 className="text-slate-500 font-medium text-sm uppercase">Pago Homologación</h3>
                <div className="text-3xl font-black text-slate-800 mt-1">{formatCOP(GOALS.homologacion)}</div>
             </div>
             <div className="bg-white p-6 rounded-2xl shadow-xl border border-slate-100 relative overflow-hidden">
                <div className="flex justify-between items-start mb-6"><div className="flex flex-col"><h3 className="text-slate-500 font-medium text-sm uppercase">Deuda Final Proyectada</h3></div></div>
                <div className={`text-2xl font-black ${totalDebtRemaining === 0 ? 'text-emerald-500' : 'text-slate-800'}`}>{formatCOP(totalDebtRemaining)}</div>
