               </div>
               <div className="flex items-center gap-6 text-sm">
                  {period.periodStats.income > 0 && <div className="flex flex-col items-end"><span className="text-[10px] uppercase text-emerald-600/70 font-bold tracking-wider">Entra</span><span className="font-bold text-emerald-600">+{formatCOP(period.periodStats.income)}</span></div>}
                  {period.periodStats.expenses > 0 && <div className="flex flex-col items-end"><span className="text-[10px] uppercase text-slate-400 font-bold tracking-wider">Sale</span><span className="font-bold text-slate-600">-{formatCOP(period.periodStats.expenses)}</span></div>}
               </div>
            </div>
            <div className="divide-y divide-slate-50">
               {period.visibleTransactions.map((t, tIdx) => (
                 <div key={tIdx} className={`px-5 py-4 flex items-center justify-between hover:bg-slate-50/80 transition-all ${t.type === 'interest' ? 'opacity-60 bg-slate-50/30 font-semibold italic' : ''}`}>
                    <div className="flex items-center gap-4">
                       <div className={`w-10 h-10 rounded-full flex items-center justify-center bg-white border shadow-sm transition-transform ${t.type === 'income' ? 'border-emerald-100 bg-emerald-50/30' : 'border-slate-100'}`}>{getIconForType(t.type)}</div>
                       <div className="flex flex-col"><span className={`text-sm font-semibold ${t.critical ? 'text-red-600' : 'text-slate-700'}`}>{t.name}</span><span className="text-[11px] text-slate-400 font-medium">{getTypeLabel(t.type)}</span></div>
                    </div>
                    <div className="text-right">
                       <span className={`block font-mono font-bold text-sm ${t.type === 'income' ? 'text-emerald-600' : t.type === 'savings' ? 'text-teal-600' : t.type === 'interest' ? 'text-orange-500' : 'text-slate-700'}`}>{t.type === 'income' ? '+' : t.type === 'savings' ? '=' : t.type === 'interest' ? '+' : '-'}{formatCOP(t.amount)}</span>
