}

export default function App() {
  const [income, setIncome] = useState(INITIAL_INCOME);
  const [debts, setDebts] = useState<DebtConfig>(DEFAULT_DEBTS);
  const [fixedExpenses, setFixedExpenses] = useState<FixedExpensesConfig>(DEFAULT_FIXED_EXPENSES);
  const [startDay, setStartDay] = useState(5);
  const [startMonth, setStartMonth] = useState(2); // Marzo (Base 0)
  const [showVariablesEditor, setShowVariablesEditor] = useState(false);
  const [simulation, setSimulation] = useState<Period[]>([]);

  useEffect(() => {
    const dates = getQuincenaDates(startDay, startMonth);
    let currentHomologacionPending = GOALS.homologacion;
    let debtAmex = debts.amex;
    let debtNu = debts.nu;
    let debtBogota = debts.bogota;

    const newSimulation: Period[] = [];
    dates.forEach((dateObj, index) => {
      const { day, month, year } = dateObj;
      const dateStr = `${day} ${getMonthShortName(month)}`;
      const incomePerQuincena = income / 2;
      let cashAvailable = incomePerQuincena;
      const transactions: Transaction[] = [];

      // --- LOGICA DE INTERESES (Solo el día 5 de cada mes) ---
      if (day === 5) {
        if (debtAmex > 0) {
          const interest = debtAmex * INTEREST_RATES.amex;
          debtAmex += interest;
          transactions.push({ id: `int-amex-${index}`, type: 'interest', name: 'Interés Mensual AMEX', amount: interest });
        }
        if (debtNu > 0) {
          const interest = debtNu * INTEREST_RATES.nu;
          debtNu += interest;
          transactions.push({ id: `int-nu-${index}`, type: 'interest', name: 'Interés Mensual NU', amount: interest });
        }
        if (debtBogota > 0) {
          const interest = debtBogota * INTEREST_RATES.bogota;
          debtBogota += interest;
          transactions.push({ id: `int-bogo-${index}`, type: 'interest', name: 'Interés Mensual Bogotá', amount: interest });
        }
      }

      // 1. Ingreso de Nómina
      transactions.push({ id: `inc-${index}`, type: 'income', name: 'Nómina Recibida', amount: incomePerQuincena });

      // 2. Prioridad 1: Gastos Fijos (Inamovibles)
      const bebeCost = fixedExpenses.bebe / 2;
      cashAvailable -= bebeCost;
      transactions.push({ id: `bebe-${index}`, type: 'fixed', name: 'Bebé (Proporcional)', amount: bebeCost, critical: true });

      if (day === 5) {
        cashAvailable -= fixedExpenses.emiliano;
        transactions.push({ id: `emi-${index}`, type: 'fixed', name: 'Emiliano', amount: fixedExpenses.emiliano, critical: true });
        cashAvailable -= fixedExpenses.internet;
        transactions.push({ id: `net-${index}`, type: 'fixed', name: 'Internet/Servicios', amount: fixedExpenses.internet, critical: true });
      } else { 
        cashAvailable -= fixedExpenses.renta;
        transactions.push({ id: `rent-${index}`, type: 'fixed', name: 'Arriendo Vivienda', amount: fixedExpenses.renta, critical: true });
      }

      // 3. Prioridad 2: Metas de Corto Plazo (Homologación)
      if (currentHomologacionPending > 0) {
        const payAmount = Math.min(cashAvailable, currentHomologacionPending);
        if (payAmount > 0) {
            currentHomologacionPending -= payAmount;
            cashAvailable -= payAmount;
            transactions.push({ id: `homo-${index}`, type: 'priority', name: 'Homologación (Fondo)', amount: payAmount, critical: true });
        }
      }

      // 4. Prioridad 3: Cuotas Mínimas (Evitar Mora)
      // Definimos cuotas mínimas automáticas (aprox 4% del saldo para tarjetas)
      const minAmex = day === 5 && debtAmex > 0 ? Math.min(debtAmex, 100000) : 0;
      const minNu = day === 20 && debtNu > 0 ? Math.min(debtNu, 150000) : 0;
      const minBogo = day === 5 && debtBogota > 0 ? debts.bogotaCuota : 0;

      if (minAmex > 0 && cashAvailable >= minAmex) {
          debtAmex -= minAmex;
          cashAvailable -= minAmex;
          transactions.push({ id: `min-amex-${index}`, type: 'debt-min', name: 'Mínimo AMEX', amount: minAmex });
      }
      if (minNu > 0 && cashAvailable >= minNu) {
          debtNu -= minNu;
          cashAvailable -= minNu;
          transactions.push({ id: `min-nu-${index}`, type: 'debt-min', name: 'Mínimo NU', amount: minNu });
      }
      if (minBogo > 0 && cashAvailable >= minBogo) {
          // Ya sabemos que en Bogotá el capital es cuota - interés. 
          // Como ya sumamos el interés arriba, la cuota baja directo el saldo total aquí.
          debtBogota -= minBogo;
          cashAvailable -= minBogo;
          transactions.push({ id: `min-bogo-${index}`, type: 'debt-min', name: 'Cuota Bogotá', amount: minBogo });
      }

      // 5. Prioridad 4: Abonos a Capital (Snowball - Deuda más pequeña primero)
      // Buffer de seguridad para imprevistos
      const SAFE_BUFFER = 100000;
      let surplus = Math.max(0, cashAvailable - SAFE_BUFFER);

      if (surplus > 0) {
          // 1. AMEX (Más pequeña)
          if (debtAmex > 0) {
              const pay = Math.min(surplus, debtAmex);
              debtAmex -= pay;
              cashAvailable -= pay;
              surplus -= pay;
              transactions.push({ id: `cap-amex-${index}`, type: 'debt-capital', name: 'Extra Capital AMEX', amount: pay });
          }
          // 2. NU (Media)
          if (surplus > 0 && debtNu > 0) {
              const pay = Math.min(surplus, debtNu);
              debtNu -= pay;
              cashAvailable -= pay;
              surplus -= pay;
              transactions.push({ id: `cap-nu-${index}`, type: 'debt-capital', name: 'Extra Capital NU', amount: pay });
          }
          // 3. Bogotá (Más grande)
          if (surplus > 0 && debtBogota > 0) {
              const pay = Math.min(surplus, debtBogota);
              debtBogota -= pay;
              cashAvailable -= pay;
              surplus -= pay;
              transactions.push({ id: `cap-bogo-${index}`, type: 'debt-capital', name: 'Extra Capital Bogotá', amount: pay });
          }
      }

      // 6. Saldo a Favor / Ahorro
      if (cashAvailable > 0) {
        const isDebtFree = (debtAmex + debtNu + debtBogota) <= 1000;
        transactions.push({ 
            id: `save-${index}`, 
            type: 'savings', 
            name: isDebtFree ? 'Ahorro Real' : 'Reserva Operativa', 
            amount: cashAvailable 
        });
      }

      newSimulation.push({
        dateStr, day, month, year,
        totalIncome: incomePerQuincena,
        transactions,
        endBalance: cashAvailable,
        debtStatus: { 
            amex: Math.round(Math.max(0, debtAmex)), 
            nu: Math.round(Math.max(0, debtNu)), 
            bogota: Math.round(Math.max(0, debtBogota)) 
        },
        goalsStatus: { homologacion: Math.max(0, currentHomologacionPending) }
      });
    });
    setSimulation(newSimulation);
  }, [income, debts, fixedExpenses, startDay, startMonth]); 

  const finalState = simulation[simulation.length - 1] || { debtStatus: { amex: 0, nu: 0, bogota: 0 }, goalsStatus: { homologacion: 0 } };
  const totalDebtRemaining = finalState.debtStatus.amex + finalState.debtStatus.nu + finalState.debtStatus.bogota;

  const chartData = simulation.map(p => ({ 
    name: p.dateStr, 
    Deuda: p.debtStatus.amex + p.debtStatus.nu + p.debtStatus.bogota 
  }));

  const savingsData = useMemo(() => {
    let accumulated = 0;
    return simulation.map(p => {
        const periodSavings = p.transactions.filter(t => t.type === 'savings').reduce((sum, t) => sum + t.amount, 0);
        accumulated += periodSavings;
        return { name: p.dateStr, Acumulado: accumulated };
    });
  }, [simulation]);

  const handleDownloadCSV = () => {
    let csv = "Fecha,Concepto,Tipo,Monto,Saldo Deuda Total\n";
    simulation.forEach(p => {
        const totalDebt = p.debtStatus.amex + p.debtStatus.nu + p.debtStatus.bogota;
        p.transactions.forEach(t => { csv += `${p.dateStr},${t.name},${t.type},${t.amount},${totalDebt}\n`; });
    });
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.setAttribute("download", `plan_financiero_${MONTH_NAMES[startMonth]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen pb-12 bg-slate-50 font-sans">
      <header className="relative overflow-hidden bg-slate-900 text-white pb-24 pt-10 px-4 md:px-8">
        <div className="absolute top-0 left-0 w-full h-full overflow-hidden z-0">
           <div className="absolute top-[-20%] right-[-10%] w-[500px] h-[500px] bg-emerald-600/10 rounded-full blur-[100px]"></div>
           <div className="absolute bottom-[-10%] left-[-10%] w-[400px] h-[400px] bg-indigo-600/10 rounded-full blur-[100px]"></div>
        </div>

        <div className="max-w-6xl mx-auto relative z-10">
          <div className="flex justify-between items-start md:items-center flex-col md:flex-row gap-6 mb-8">
            <div>
              <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-slate-800/80 border border-slate-700 backdrop-blur-md mb-3 text-xs text-emerald-100">
                 <Clock size={12} className="text-emerald-400" /> Plan Optimizado Iniciando el {startDay} de {MONTH_NAMES[startMonth]}
              </div>
              <h1 className="text-3xl md:text-5xl font-black tracking-tight">Finanzas 2026</h1>
              <p className="text-slate-400 mt-2 text-lg max-w-2xl font-light">Estrategia de eliminación de deuda acelerada con cálculo de intereses reales.</p>
            </div>
            <div className="flex flex-wrap gap-3 no-print">
               <button onClick={() => setShowVariablesEditor(!showVariablesEditor)} className={`px-5 py-2.5 rounded-xl text-sm font-semibold flex items-center gap-2 transition-all shadow-lg ${showVariablesEditor ? 'bg-white text-slate-900' : 'bg-slate-800/80 hover:bg-slate-700 text-white border border-slate-700'}`}><Edit3 size={18} /> Ajustar Plan</button>
               <button onClick={handleDownloadCSV} className="bg-slate-800/80 hover:bg-slate-700 text-white px-5 py-2.5 rounded-xl text-sm font-semibold flex items-center gap-2 transition-all border border-slate-700"><Download size={18} /> Exportar Plan</button>
            </div>
          </div>
          {showVariablesEditor && (
             <VariablesEditor 
                currentDebts={debts} 
                currentExpenses={fixedExpenses} 
                startDay={startDay} 
                startMonth={startMonth} 
                onClose={() => setShowVariablesEditor(false)} 
                onSave={(newDebts, newExpenses, day, month) => {
                    setDebts(newDebts);
                    setFixedExpenses(newExpenses);
                    setStartDay(day);
                    setStartMonth(month);
                }} 
             />
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 md:px-8 -mt-16 relative z-20">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
             <div className="bg-white p-6 rounded-2xl shadow-xl border border-slate-100">
                <div className="flex justify-between items-start mb-4"><div className="p-3 bg-indigo-50 rounded-xl text-indigo-600"><GraduationCap size={24} /></div></div>
                <h3 className="text-slate-500 font-medium text-sm uppercase">Pendiente Homologación</h3>
                <div className="text-3xl font-black text-slate-800 mt-1">{formatCOP(finalState.goalsStatus.homologacion)}</div>
                <p className="text-[10px] text-slate-400 mt-2">Prioridad máxima en el flujo de caja</p>
             </div>
             <div className="bg-white p-6 rounded-2xl shadow-xl border border-slate-100 relative overflow-hidden">
                <div className="flex justify-between items-start mb-6"><div className="flex flex-col"><h3 className="text-slate-500 font-medium text-sm uppercase">Deuda Total Restante</h3></div></div>
                <div className={`text-2xl font-black ${totalDebtRemaining === 0 ? 'text-emerald-500' : 'text-slate-800'}`}>{formatCOP(totalDebtRemaining)}</div>
                <div className="h-1.5 w-full bg-slate-100 rounded-full mt-4 overflow-hidden">
                    <div className="h-full bg-emerald-500 transition-all duration-1000" style={{ width: `${Math.max(5, 100 - (totalDebtRemaining / (debts.amex + debts.nu + debts.bogota)) * 100)}%` }}></div>
                </div>
             </div>
             <div className="bg-gradient-to-br from-slate-800 to-slate-900 p-6 rounded-2xl shadow-xl border border-slate-700 text-white">
                <h3 className="font-bold text-lg mb-4 flex items-center gap-2"><Wallet size={18} className="text-emerald-400"/> Resumen de Ingresos</h3>
                <div className="space-y-4 text-sm text-slate-300">
                  <div className="flex justify-between border-b border-slate-700 pb-2"><span>Nómina Mensual</span><span className="text-white font-mono">{formatCOP(income)}</span></div>
                  <div className="flex justify-between border-b border-slate-700 pb-2"><span>Arriendo (Día 20)</span><span className="text-orange-400 font-mono">{formatCOP(fixedExpenses.renta)}</span></div>
                </div>
             </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-12">
            <DebtEliminationChart data={chartData} />
            <SavingsGrowthChart data={savingsData} />
        </div>

        <section className="relative">
            <div className="absolute left-8 top-12 bottom-0 w-0.5 bg-slate-200 hidden md:block"></div>
            <h2 className="text-xl font-bold text-slate-800 mb-8 flex items-center gap-2 relative z-10">
                <Calendar className="text-indigo-600" size={24}/> 
                Ruta de Acción: Próximas 12 Quincenas
            </h2>
            <div className="space-y-8 relative z-10">
                {simulation.map((period, idx) => (
                    <div key={idx} className="relative pl-0 md:pl-20">
                        <div className="absolute left-4 top-8 w-8 h-8 rounded-full bg-slate-50 border-4 border-white shadow-md z-10 hidden md:flex items-center justify-center">
                            <div className={`w-2.5 h-2.5 rounded-full ${period.day === 5 ? 'bg-indigo-500' : 'bg-orange-500'}`}></div>
                        </div>
                        <div className="absolute left-[-10px] top-8 w-24 text-right pr-4 hidden md:block">
                             <div className="text-xs font-bold text-slate-400 uppercase tracking-tight">{getMonthShortName(period.month)} {period.year}</div>
                             <div className="text-lg font-black text-slate-700">{period.day}</div>
                        </div>
                        <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden hover:shadow-lg transition-all duration-300">
                            <div className="flex bg-slate-50/30 px-6 py-3 border-b border-slate-100 justify-between items-center">
                                 <span className="text-sm font-semibold text-slate-600">
                                    {period.day === 5 ? 'Distribución Primera Quincena' : 'Distribución Segunda Quincena'}
                                 </span>
                                 <span className="text-xs font-medium text-slate-400">
                                    Colchón Final: <span className="text-emerald-600 font-bold">{formatCOP(period.endBalance)}</span>
                                 </span>
                            </div>
                            <div className="p-5 md:p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
                                <div>
                                    <h4 className="text-[10px] font-bold text-slate-400 uppercase mb-4 tracking-widest flex items-center gap-2">
                                        <div className="w-1.5 h-1.5 rounded-full bg-slate-300"></div> Pagos Obligatorios
                                    </h4>
                                    <ul className="space-y-3">
                                        {period.transactions.filter(t => ['fixed', 'priority', 'debt-min', 'interest'].includes(t.type)).map(t => (
                                            <li key={t.id} className="flex justify-between items-center text-sm">
                                                <div className="flex items-center gap-2">
                                                    {t.type === 'interest' ? <Percent size={12} className="text-orange-400"/> : <CheckCircle2 size={12} className="text-slate-300"/>}
                                                    <span className={`${t.type === 'interest' ? 'text-orange-600 italic font-medium' : t.type === 'priority' ? 'font-bold text-indigo-700' : 'text-slate-600'}`}>
                                                        {t.name}
                                                    </span>
                                                </div>
                                                <span className={`text-slate-900 font-mono ${t.type === 'interest' ? 'text-orange-500' : ''}`}>
                                                    {t.type === 'interest' ? '+' : '-'}{formatCOP(t.amount)}
                                                </span>
