                                </div>
                                <div>
                                    <h4 className="text-[10px] font-bold text-slate-400 uppercase mb-4 tracking-widest flex items-center gap-2">
                                        <div className="w-1.5 h-1.5 rounded-full bg-emerald-400"></div> Estrategia Capital
                                    </h4>
                                    <ul className="space-y-3">
                                        {period.transactions.filter(t => ['debt-capital', 'savings'].includes(t.type)).map(t => (
                                            <li key={t.id} className="flex justify-between items-center text-sm">
                                                <span className={`${t.type === 'debt-capital' ? 'font-semibold text-purple-700' : 'text-teal-700 font-medium'}`}>{t.name}</span>
                                                <span className="text-slate-900 font-mono">{t.type === 'savings' ? '' : '-'}{formatCOP(t.amount)}</span>
