  );
}

// --- App Principal ---

export default function App() {
  // Lógica de carga desde LocalStorage
  const [debts, setDebts] = useState<DebtConfig>(() => {
    const saved = localStorage.getItem('finanzas_2026_debts');
    return saved ? JSON.parse(saved) : DEFAULT_DEBTS;
  });

  const [expenses, setExpenses] = useState<FixedExpensesConfig>(() => {
    const saved = localStorage.getItem('finanzas_2026_expenses');
    return saved ? JSON.parse(saved) : DEFAULT_FIXED_EXPENSES;
  });

  const [startDay, setStartDay] = useState<number>(() => {
    const saved = localStorage.getItem('finanzas_2026_startDay');
    return saved ? Number(saved) : 20; // Default a la quincena del 20
  });

  const [startMonth, setStartMonth] = useState<number>(() => {
    const saved = localStorage.getItem('finanzas_2026_startMonth');
    return saved ? Number(saved) : 1; // Default a Febrero (Base 0 es Ene)
  });

  const [showEditor, setShowEditor] = useState(false);
  const [simulation, setSimulation] = useState<Period[]>([]);
  const [lastSaved, setLastSaved] = useState<string>("");

  // Efecto para guardar automáticamente cada vez que algo cambie
  useEffect(() => {
    localStorage.setItem('finanzas_2026_debts', JSON.stringify(debts));
    localStorage.setItem('finanzas_2026_expenses', JSON.stringify(expenses));
    localStorage.setItem('finanzas_2026_startDay', startDay.toString());
    localStorage.setItem('finanzas_2026_startMonth', startMonth.toString());

    const now = new Date();
    setLastSaved(`${now.getHours()}:${now.getMinutes().toString().padStart(2, '0')}`);
  }, [debts, expenses, startDay, startMonth]);

  useEffect(() => {
    const dates = getQuincenaDates(startDay, startMonth);
    let dAmex = debts.amex;
    let dNu = debts.nu;
    let dBogota = debts.bogota;

    const newSim: Period[] = [];

    dates.forEach((d, i) => {
      const dateStr = `${d.day} ${getMonthShortName(d.month)}`;
      const inc = INITIAL_INCOME / 2;
      let cash = inc;
      const txs: Transaction[] = [];

      txs.push({ id: `inc-${i}`, type: 'income', name: 'Nómina', amount: inc });

      // 1. Gastos Fijos (Inamovibles)
      const bCost = expenses.bebe / 2; 
      cash -= bCost;
      txs.push({ id: `be-${i}`, type: 'fixed', name: 'Bebé', amount: bCost, critical: true });

      if (d.day === 5) { 
        cash -= expenses.emiliano + expenses.internet; 
        txs.push({ id: `ex-${i}`, type: 'fixed', name: 'Emiliano/Internet', amount: expenses.emiliano + expenses.internet });
      } else { 
        cash -= expenses.renta; 
        txs.push({ id: `re-${i}`, type: 'fixed', name: 'Arriendo', amount: expenses.renta, critical: true });
      }

      // NO HAY HOMOLOGACIÓN (Ya está financiada según usuario)

      // 2. Cuotas Obligatorias
      const mBogo = d.day === 5 && dBogota > 0 ? debts.bogotaCuota : 0;
      if (mBogo > 0 && cash >= mBogo) { 
          dBogota -= mBogo; 
          cash -= mBogo; 
          txs.push({ id: `mb-${i}`, type: 'debt-min', name: 'Cuota Bogotá', amount: mBogo }); 
      }

      // 3. Estrategia de Capital (Snowball acelerado)
      const buffer = 100000; 
      let surplus = Math.max(0, cash - buffer);

      if (surplus > 0) {
        // AMEX es la prioridad ahora (1.8M)
        if (dAmex > 0) { 
            const p = Math.min(surplus, dAmex); 
            dAmex -= p; 
            cash -= p; 
            surplus -= p; 
            txs.push({ id: `ca-${i}`, type: 'debt-capital', name: 'Abono AMEX', amount: p }); 
        }

        // NU es la siguiente (2M)
        if (surplus > 0 && dNu > 0) { 
            const p = Math.min(surplus, dNu); 
            dNu -= p; 
            cash -= p; 
            surplus -= p; 
            txs.push({ id: `cn-${i}`, type: 'debt-capital', name: 'Abono NU', amount: p }); 
        }

        // Bogotá finalmente
        if (surplus > 0 && dBogota > 0) { 
            const p = Math.min(surplus, dBogota); 
            dBogota -= p; 
            cash -= p; 
            surplus -= p; 
            txs.push({ id: `cb-${i}`, type: 'debt-capital', name: 'Extra Bogotá', amount: p }); 
        }
      }

      // 4. Saldo disponible final
      if (cash > 0) { 
          const isDebtFree = (dAmex + dNu + dBogota) <= 1000;
          txs.push({ id: `sv-${i}`, type: 'savings', name: isDebtFree ? 'Ahorro Real' : 'Caja para Imprevistos', amount: cash }); 
      }

      newSim.push({
        dateStr, day: d.day, month: d.month, year: d.year, 
        transactions: txs, endBalance: cash,
        debtStatus: { amex: Math.round(Math.max(0, dAmex)), nu: Math.round(Math.max(0, dNu)), bogota: Math.round(Math.max(0, dBogota)) }
      });
    });
    setSimulation(newSim);
  }, [debts, expenses, startDay, startMonth]);

  const currentTotalDebt = debts.amex + debts.nu + debts.bogota;
  const chartData = simulation.map(p => ({ name: p.dateStr, Deuda: p.debtStatus.amex + p.debtStatus.nu + p.debtStatus.bogota }));
  const savingsData = useMemo(() => {
    let acc = 0; return simulation.map(p => { acc += p.transactions.filter(t => t.type === 'savings').reduce((s, t) => s + t.amount, 0); return { name: p.dateStr, Acumulado: acc }; });
  }, [simulation]);

  return (
    <div className="min-h-screen bg-slate-50">
      <header className="bg-slate-900 text-white pt-10 pb-24 px-6 md:px-12 relative overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-br from-indigo-900/20 to-emerald-900/20 pointer-events-none" />
        <div className="max-w-6xl mx-auto relative z-10">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-8 mb-4">
            <div>
              <div className="flex items-center gap-2 text-emerald-400 text-xs font-bold uppercase mb-2">
                <Clock size={14}/> Hoy es 15 de Febrero • Simulación desde el {startDay} de {MONTH_NAMES[startMonth]}
              </div>
              <h1 className="text-4xl font-black mb-2 tracking-tight">Finanzas Personales 2026</h1>
              <p className="text-slate-400 font-light max-w-lg">Saldos actualizados y guardado persistente. Homologación financiada ✅.</p>
            </div>
            <div className="flex flex-col items-end gap-3 h-fit">
              <button onClick={() => setShowEditor(!showEditor)} className="bg-white text-slate-900 px-5 py-2.5 rounded-xl font-bold flex items-center gap-2 hover:bg-emerald-50 transition-all shadow-lg active:scale-95"><Edit3 size={18}/> Actualizar Saldos</button>
              <div className="flex items-center gap-2 text-[10px] text-slate-500 font-medium bg-slate-800/50 px-3 py-1 rounded-full">
                <Save size={10} className="text-emerald-500" /> Cambios guardados localmente: {lastSaved}
              </div>
            </div>
          </div>
          {showEditor && <VariablesEditor debts={debts} expenses={expenses} startDay={startDay} startMonth={startMonth} onSave={(d:any, e:any, day:number, m:number) => { setDebts(d); setExpenses(e); setStartDay(day); setStartMonth(m); }} onClose={() => setShowEditor(false)} />}
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-6 md:px-12 -mt-12 relative z-20 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-xl border border-slate-100 group hover:border-indigo-100 transition-colors">
            <CheckCircle2 className="text-indigo-600 mb-4" size={32}/>
            <h3 className="text-slate-500 text-xs font-bold uppercase tracking-wider">Homologación</h3>
            <div className="text-3xl font-black text-emerald-600">PAGADO</div>
            <p className="text-[10px] text-slate-400 mt-2">Capital ya asegurado fuera del flujo</p>
          </div>
          <div className="bg-white p-6 rounded-2xl shadow-xl border border-slate-100 group hover:border-rose-100 transition-colors">
            <TrendingDown className="text-rose-500 mb-4" size={32}/>
            <h3 className="text-slate-500 text-xs font-bold uppercase tracking-wider">Deuda Actual</h3>
            <div className="text-3xl font-black text-slate-800">{formatCOP(currentTotalDebt)}</div>
            <div className="w-full bg-slate-100 h-1.5 rounded-full mt-3 overflow-hidden">
                <div className="bg-rose-500 h-full rounded-full transition-all duration-1000" style={{ width: '100%' }} />
            </div>
            <p className="text-[10px] text-slate-400 mt-2">Suma de AMEX, NU y Bogotá</p>
          </div>
          <div className="bg-slate-800 p-6 rounded-2xl shadow-xl text-white border border-slate-700">
            <Wallet className="text-emerald-400 mb-4" size={32}/>
            <h3 className="text-slate-400 text-xs font-bold uppercase tracking-wider">Nómina Fija</h3>
            <div className="text-3xl font-black">{formatCOP(INITIAL_INCOME)}</div>
            <p className="text-[10px] text-slate-500 mt-2">Ingreso mensual proyectado</p>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <DebtEliminationChart data={chartData} />
          <SavingsGrowthChart data={savingsData} />
        </div>

        <section className="bg-white rounded-3xl p-6 md:p-8 shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-8">
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-3">
              <Calendar className="text-indigo-600"/> Ruta de Pagos (Próximos 6 Meses)
            </h2>
            <div className="px-3 py-1 bg-slate-50 text-[10px] font-bold text-slate-400 rounded-lg border border-slate-100">
                ACTUALIZADO: {MONTH_NAMES[startMonth].toUpperCase()} {startDay}
            </div>
          </div>
          <div className="space-y-12">
            {simulation.map((p, i) => (
              <div key={i} className="relative pl-8 md:pl-24 group">
                <div className="absolute left-0 md:left-12 top-0 h-full w-0.5 bg-slate-100 group-last:h-8" />
                <div className="absolute left-[-6px] md:left-[42px] top-1 w-3.5 h-3.5 rounded-full bg-white border-4 border-indigo-500 shadow-sm transition-transform group-hover:scale-110" />
                <div className="absolute left-[-80px] top-0 hidden md:block text-right w-20">
                  <div className="text-[10px] font-black uppercase text-slate-400">{getMonthShortName(p.month)}</div>
