                <div className="bg-slate-50/50 rounded-2xl border border-slate-100 overflow-hidden transition-all hover:shadow-md hover:bg-white">
                  <div className="px-6 py-3 bg-white border-b border-slate-100 flex justify-between items-center">
                    <span className="text-sm font-bold text-slate-700">{p.day === 5 ? 'Quincena 1: Servicios' : 'Quincena 2: Arriendo'}</span>
                    <span className="text-xs font-medium text-slate-500">Caja Disponible: <span className="text-emerald-600 font-black">{formatCOP(p.endBalance)}</span></span>
                  </div>
                  <div className="p-6 grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div>
