      </div>
    </div>
  );
}

// --- App Principal ---

export default function App() {
  const [debts, setDebts] = useState<DebtConfig>(() => {
    const saved = localStorage.getItem('finanzas_v3_debts');
    return saved ? JSON.parse(saved) : DEFAULT_DEBTS;
  });

  const [expenses, setExpenses] = useState<FixedExpensesConfig>(() => {
    const saved = localStorage.getItem('finanzas_v3_expenses');
    return saved ? JSON.parse(saved) : DEFAULT_FIXED_EXPENSES;
  });

  const [startDay, setStartDay] = useState<number>(() => {
    const saved = localStorage.getItem('finanzas_v3_startDay');
    return saved ? Number(saved) : 20; 
  });

  const [startMonth, setStartMonth] = useState<number>(() => {
    const saved = localStorage.getItem('finanzas_v3_startMonth');
    return saved ? Number(saved) : 1; // Febrero
  });

  const [showEditor, setShowEditor] = useState(false);
  const [simulation, setSimulation] = useState<Period[]>([]);
  const [lastSaved, setLastSaved] = useState<string>("");

  useEffect(() => {
    localStorage.setItem('finanzas_v3_debts', JSON.stringify(debts));
    localStorage.setItem('finanzas_v3_expenses', JSON.stringify(expenses));
    localStorage.setItem('finanzas_v3_startDay', startDay.toString());
    localStorage.setItem('finanzas_v3_startMonth', startMonth.toString());
    setLastSaved(new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }));
  }, [debts, expenses, startDay, startMonth]);

  useEffect(() => {
    const dates = getQuincenaDates(startDay, startMonth);
    let dAmex = debts.amex;
    let dNu = debts.nu;
    let dBogota = debts.bogota;

    const newSim: Period[] = [];

    dates.forEach((d, i) => {
      const dateStr = `${d.day} ${getMonthShortName(d.month)}`;
      const inc = INITIAL_INCOME / 2;
      let cash = inc;
      const txs: Transaction[] = [];
      const isApril = d.month === 3; // Abril es Mes de Viaje
      const isMayOrLater = d.month >= 4;

      txs.push({ id: `inc-${i}`, type: 'income', name: 'Nómina', amount: inc });

      // 1. Gastos Fijos
      const bCost = expenses.bebe / 2; 
      cash -= bCost;
      txs.push({ id: `be-${i}`, type: 'fixed', name: 'Bebé', amount: bCost, critical: true });

      if (d.day === 5) { 
        cash -= expenses.emiliano + expenses.internet; 
        txs.push({ id: `ex-${i}`, type: 'fixed', name: 'Emiliano/Internet', amount: expenses.emiliano + expenses.internet });
      } else { 
        cash -= expenses.renta; 
        txs.push({ id: `re-${i}`, type: 'fixed', name: 'Arriendo', amount: expenses.renta, critical: true });
      }

      // 2. Cuotas Obligatorias (Bogotá siempre se paga el 5)
      const mBogo = d.day === 5 && dBogota > 0 ? debts.bogotaCuota : 0;
      if (mBogo > 0 && cash >= mBogo) { 
          dBogota -= mBogo; 
          cash -= mBogo; 
          txs.push({ id: `mb-${i}`, type: 'debt-min', name: 'Cuota Bogotá', amount: mBogo }); 
      }

      // 3. Estrategia de Capital
      // ABRIL: No hay abonos extra por viaje.
      // MAYO: Liquidación total de Bogotá si es posible.
      const buffer = isApril ? 500000 : 150000; // En abril dejamos un colchón más grande para el viaje
      let surplus = Math.max(0, cash - buffer);

      if (surplus > 0 && !isApril) {
        // AMEX (Prioridad 1)
        if (dAmex > 0) { 
            const p = Math.min(surplus, dAmex); 
            dAmex -= p; 
            cash -= p; 
            surplus -= p; 
            txs.push({ id: `ca-${i}`, type: 'debt-capital', name: 'Abono AMEX', amount: p }); 
        }

        // NU (Prioridad 2)
        if (surplus > 0 && dNu > 0) { 
            const p = Math.min(surplus, dNu); 
            dNu -= p; 
            cash -= p; 
            surplus -= p; 
            txs.push({ id: `cn-${i}`, type: 'debt-capital', name: 'Abono NU', amount: p }); 
        }

        // Bogotá (Prioridad 3 - Solo fuerte en Mayo o si sobra)
        if (surplus > 0 && dBogota > 0) {
            // Si es mayo o posterior, somos más agresivos con Bogotá según pedido
            const p = Math.min(surplus, dBogota); 
            dBogota -= p; 
            cash -= p; 
            surplus -= p; 
            txs.push({ id: `cb-${i}`, type: 'debt-capital', name: isMayOrLater ? 'Liquidación Bogotá' : 'Extra Bogotá', amount: p }); 
        }
      }

      if (cash > 0) { 
          txs.push({ id: `sv-${i}`, type: 'savings', name: isApril ? 'Fondo de Viaje' : 'Excedente', amount: cash }); 
      }

      newSim.push({
        dateStr, day: d.day, month: d.month, year: d.year, 
        transactions: txs, endBalance: cash,
        debtStatus: { amex: Math.round(Math.max(0, dAmex)), nu: Math.round(Math.max(0, dNu)), bogota: Math.round(Math.max(0, dBogota)) }
      });
    });
    setSimulation(newSim);
  }, [debts, expenses, startDay, startMonth]);

  const currentTotalDebt = debts.amex + debts.nu + debts.bogota;
  const chartData = simulation.map(p => ({ name: p.dateStr, Deuda: p.debtStatus.amex + p.debtStatus.nu + p.debtStatus.bogota }));
  const savingsData = useMemo(() => {
    let acc = 0; return simulation.map(p => { acc += p.transactions.filter(t => t.type === 'savings').reduce((s, t) => s + t.amount, 0); return { name: p.dateStr, Acumulado: acc }; });
  }, [simulation]);

  return (
    <div className="min-h-screen bg-slate-50">
      <header className="bg-slate-900 text-white pt-10 pb-24 px-6 md:px-12 relative overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-br from-indigo-900/20 to-emerald-900/20 pointer-events-none" />
        <div className="max-w-6xl mx-auto relative z-10">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-8 mb-4">
            <div>
              <div className="flex items-center gap-2 text-emerald-400 text-xs font-bold uppercase mb-2">
                <Clock size={14}/> 15 Feb • Simulación desde {startDay}/{MONTH_NAMES[startMonth]}
              </div>
              <h1 className="text-4xl font-black mb-2 tracking-tight">Estrategia Financiera 2026</h1>
              <p className="text-slate-400 font-light max-w-lg">Abril reservado para viaje. Liquidación de Bogotá proyectada para Mayo.</p>
            </div>
            <div className="flex flex-col items-end gap-3 h-fit">
              <button onClick={() => setShowEditor(!showEditor)} className="bg-white text-slate-900 px-5 py-2.5 rounded-xl font-bold flex items-center gap-2 hover:bg-emerald-50 transition-all shadow-lg active:scale-95"><Edit3 size={18}/> Actualizar Cifras</button>
              <div className="flex items-center gap-2 text-[10px] text-slate-500 font-medium bg-slate-800/50 px-3 py-1 rounded-full border border-slate-700">
                <Save size={10} className="text-emerald-500" /> Auto-guardado: {lastSaved}
              </div>
            </div>
          </div>
          {showEditor && <VariablesEditor debts={debts} expenses={expenses} startDay={startDay} startMonth={startMonth} onSave={(d:any, e:any, day:number, m:number) => { setDebts(d); setExpenses(e); setStartDay(day); setStartMonth(m); }} onClose={() => setShowEditor(false)} />}
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-6 md:px-12 -mt-12 relative z-20 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-xl border border-slate-100 flex flex-col justify-between">
            <CheckCircle2 className="text-indigo-600 mb-2" size={32}/>
            <div>
                <h3 className="text-slate-500 text-xs font-bold uppercase">Homologación</h3>
                <div className="text-2xl font-black text-emerald-600">FINANCIADO ✅</div>
            </div>
          </div>
          <div className="bg-white p-6 rounded-2xl shadow-xl border border-slate-100">
            <TrendingDown className="text-rose-500 mb-2" size={32}/>
            <h3 className="text-slate-500 text-xs font-bold uppercase">Deuda Hoy</h3>
            <div className="text-3xl font-black text-slate-800">{formatCOP(currentTotalDebt)}</div>
            <div className="flex gap-1 mt-2">
                <div className="h-1 flex-1 bg-blue-400 rounded-full" title="Amex"></div>
                <div className="h-1 flex-1 bg-purple-400 rounded-full" title="Nu"></div>
                <div className="h-1 flex-1 bg-yellow-400 rounded-full" title="Bogotá"></div>
            </div>
          </div>
          <div className="bg-slate-800 p-6 rounded-2xl shadow-xl text-white border border-slate-700">
            <Plane className="text-sky-400 mb-2" size={32}/>
            <h3 className="text-slate-400 text-xs font-bold uppercase">Viaje Abril</h3>
            <div className="text-2xl font-black">Gastos Mínimos</div>
            <p className="text-[10px] text-slate-500 mt-1 uppercase">Pausa de abonos a capital</p>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <DebtEliminationChart data={chartData} />
          <SavingsGrowthChart data={savingsData} />
        </div>

        <section className="bg-white rounded-3xl p-6 md:p-8 shadow-sm border border-slate-100">
          <h2 className="text-xl font-black text-slate-800 flex items-center gap-3 mb-8">
            <Calendar className="text-indigo-600"/> Cronograma Personalizado
          </h2>
          <div className="space-y-10">
            {simulation.map((p, i) => (
              <div key={i} className={`relative pl-8 md:pl-24 group ${p.month === 3 ? 'opacity-90' : ''}`}>
                <div className="absolute left-0 md:left-12 top-0 h-full w-0.5 bg-slate-100 group-last:h-8" />
                <div className={`absolute left-[-6px] md:left-[42px] top-1 w-3.5 h-3.5 rounded-full bg-white border-4 shadow-sm transition-transform group-hover:scale-110 ${p.month === 3 ? 'border-sky-500' : 'border-indigo-500'}`} />
                <div className="absolute left-[-80px] top-0 hidden md:block text-right w-20">
                  <div className={`text-[10px] font-black uppercase ${p.month === 3 ? 'text-sky-500' : 'text-slate-400'}`}>{getMonthShortName(p.month)}</div>
                  <div className="text-xl font-black text-slate-700">{p.day}</div>
                </div>

                <div className={`bg-slate-50/50 rounded-2xl border overflow-hidden transition-all hover:shadow-md hover:bg-white ${p.month === 3 ? 'border-sky-100' : 'border-slate-100'}`}>
                  <div className={`px-6 py-2 border-b flex justify-between items-center ${p.month === 3 ? 'bg-sky-50 border-sky-100' : 'bg-white border-slate-100'}`}>
                    <div className="flex items-center gap-2">
                        <span className="text-xs font-bold text-slate-700">{p.day === 5 ? 'Q1' : 'Q2'}</span>
                        {p.month === 3 && <span className="text-[10px] bg-sky-200 text-sky-800 px-2 py-0.5 rounded-full font-bold flex items-center gap-1"><Plane size={10}/> VIAJE</span>}
                        {p.month === 4 && <span className="text-[10px] bg-yellow-100 text-yellow-800 px-2 py-0.5 rounded-full font-bold flex items-center gap-1"><Landmark size={10}/> LIQUIDACIÓN BOGOTÁ</span>}
                    </div>
                    <span className="text-[10px] font-medium text-slate-500 uppercase tracking-tight">Disponible: <span className="text-emerald-600 font-black">{formatCOP(p.endBalance)}</span></span>
                  </div>
                  <div className="p-5 grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div>
                      <h4 className="text-[9px] font-black uppercase text-slate-400 tracking-widest mb-3">Compromisos</h4>
                      <ul className="space-y-2">
                        {p.transactions.filter(t => ['fixed', 'debt-min'].includes(t.type)).map(t => (
                          <li key={t.id} className="flex justify-between text-xs items-center">
