                          </li>
                        ))}
                        {p.transactions.filter(t => t.type === 'debt-capital').length === 0 && p.month === 3 && (
                            <li className="text-[10px] text-sky-600 italic font-medium">No se realizan abonos este mes por el viaje.</li>
                        )}
                      </ul>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </section>
      </main>
      <footer className="max-w-6xl mx-auto px-6 py-12 text-center">
